INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNT_2016_parent', 'VNT', 2016, 'parent', 'Công ty có giao dịch đáng kể với công ty con Công ty TNHH Giao nhận vận tải Hà Thành, bao gồm trả trước cho người bán 20 tỷ VND và doanh thu bán dịch vụ 16,8 tỷ VND. Tổng Giám đốc Nguyễn Xuân Giang dùng sổ tiết kiệm cá nhân để bảo lãnh khoản vay công ty. Ban lãnh đạo có tạm ứng cá nhân 527 triệu VND. Các giao dịch này có tính chất hợp lý nhưng cần theo dõi mức độ tập trung giao dịch với bên liên quan.', 'Nợ vay ngắn hạn rất lớn 134,2 tỷ VND từ nhiều ngân hàng, tăng mạnh so với 87,4 tỷ VND đầu năm. Công ty phát hành trái phiếu chuyển đổi 720.000 trái phiếu mệnh giá 100.000 VND với lãi suất 8%/năm và thả nổi. Chi phí lãi vay tăng gần 3 lần từ 3,4 tỷ lên 9,9 tỷ VND. Tuy nhiên, công ty có tài sản thế chấp bao gồm TSCĐ, ký quỹ ngân hàng và bảo lãnh cá nhân của CEO.', 'Chi phí xây dựng cơ bản dở dang giảm mạnh từ 14,4 tỷ xuống 1,3 tỷ VND, chủ yếu do dự án kho trung chuyển tại Hải Phòng hoàn thành và chuyển ghi nhận vào TSCĐ hữu hình. Không có hàng tồn kho dở dang đáng lo ngại.', 6, 'Công ty ghi nhận doanh thu 464,8 tỷ VND và lợi nhuận sau thuế 21,9 tỷ VND trong năm 2016. Biên lợi nhuận gộp ~10,1%. Công ty đang trong giai đoạn mở rộng mạnh với khoản đặt cọc 240 tỷ VND mua lại cổ phần Cảng MIPEC và phát hành trái phiếu chuyển đổi. Nợ vay tăng mạnh, áp lực lãi vay lớn. Dòng tiền hoạt động kinh doanh âm 1,56 tỷ VND do tăng mạnh phải thu và giảm phải trả. Cần theo dõi khả năng quản lý dòng tiền và tỷ lệ đòn bẩy tài chính.'),
('VNT_2015_consolidated', 'VNT', 2015, 'consolidated', 'Công ty có giao dịch với Tổng Giám đốc (thế chấp cho khoản vay) nhưng giá trị không quá lớn. Thù lao HĐQT và Ban Tổng Giám đốc được công bố minh bạch, không phát hiện giao dịch bất thường đáng ngờ.', 'Nợ vay ngắn hạn tăng mạnh với tổng dư nợ 87,355,508,433 VND, áp lực trả nợ cao. Một phần khoản vay được bảo đảm bằng tài sản như quyền sử dụng đất và sổ tiết kiệm, giảm rủi ro.', 'Chi phí xây dựng dở dang tăng từ 2,777,388,429 VND lên 14,419,325,635 VND, cần theo dõi tiến độ dự án và khả năng hoàn thành đúng hạn.', 5, 'Tập đoàn có doanh thu và lợi nhuận tăng trưởng, biên lợi nhuận gộp ổn định khoảng 8.23%. Tuy nhiên, nợ vay ngắn hạn tăng cao dẫn đến áp lực tài chính. Các giao dịch liên quan được kiểm soát tương đối, quản trị ở mức trung bình.'),
('VNT_2016_consolidated', 'VNT', 2016, 'consolidated', 'Giao dịch với bên liên quan có một số dấu hiệu rủi ro: (1) Khoản tạm ứng 527.637.352 VND cho HĐQT và Ban Tổng Giám đốc không rõ lãi suất và thời hạn; (2) Ông Nguyễn Xuân Giang (Chủ tịch HĐQT kiêm Tổng Giám đốc) dùng sổ tiết kiệm cá nhân trị giá 4.470.000.000 VND bảo đảm cho khoản vay 20.000.000.000 VND của Công ty tại LienVietPostBank - cho thấy sự thiếu tách bạch giữa tài sản cá nhân và tài sản công ty; (3) Vinatrans - cổ đông lớn 10,48% cho Công ty vay ngắn hạn 39 tỷ VND với lãi suất 8,5-9%/năm (cao hơn lãi suất ngân hàng 7,5%); (4) Khoản đặt cọc 240 tỷ VND mua cổ phần Cảng MIPEC từ Công ty Hóa Dầu Quân Đội chưa hoàn tất, tiềm ẩn rủi ro mất vốn.', 'Áp lực nợ vay tăng mạnh: nợ ngắn hạn tăng từ 87 tỷ lên 134 tỷ VND, nợ dài hạn phát sinh thêm 72 tỷ VND (bao gồm trái phiếu chuyển đổi 71,4 tỷ VND). Tổng nợ vay chiếm tỷ trọng cao. Chi phí lãi vay tăng gần 3 lần từ 3,4 tỷ lên 9,9 tỷ VND. Công ty có tài sản đảm bảo đa dạng (quyền sử dụng đất, sổ tiết kiệm cá nhân Tổng Giám đốc, ô tô). Việc phát hành trái phiếu chuyển đổi cho đối tác Nhật Bản Mitsui Wharf là tín hiệu tích cực về uy tín, nhưng cũng tạo nghĩa vụ chuyển đổi cổ phần trong tương lai.', 'Công ty hoạt động trong lĩnh vực giao nhận vận tải nên không có hàng tồn kho truyền thống. Chỉ có khoản đầu tư xây dựng kho trung chuyển Hải Phòng (1,2 tỷ VND) đang dở dang, đã giảm đáng kể so với đầu năm (14,3 tỷ VND) cho thấy dự án phần lớn đã hoàn thành hoặc thoái vốn. Rủi ro tồn kho ở mức thấp.', 6, 'Công ty Cổ phần Giao Nhận Vận Tải Ngoại Thương hoạt động trong ngành giao nhận, logistics với kết quả kinh doanh tương đối ổn định nhưng tăng trưởng âm (doanh thu giảm từ 779 tỷ xuống 680 tỷ VND, lợi nhuận sau thuế giảm từ 28,9 tỷ xuống 21,9 tỷ VND). Nợ vay tăng mạnh đáng lo ngại, phản ánh hoạt động mở rộng quy mô (đặt cọc mua Cảng MIPEC 240 tỷ VND, phát hành trái phiếu chuyển đổi 71,4 tỷ VND). Các giao dịch với bên liên quan cần được giám sát chặt chẽ, đặc biệt khi Chủ tịch HĐQT kiêm Tổng Giám đốc và có giao dịch tài chính cá nhân với công ty. Có tín hiệu tích cực từ việc phát hành trái phiếu chuyển đổi cho nhà đầu tư Nhật Bản Mitsui Wharf.'),
('VNSC_2025_consolidated', 'VNSC', 2025, 'consolidated', 'Công ty có giao dịch mua bán trái phiếu lớn với Công ty Cổ phần Finhay Việt Nam (công ty liên quan qua công ty mẹ), phát sinh doanh thu/chi phí đáng kể. Đồng thời, vay vốn từ Finhay Tech SG Pte. Ltd. với Chủ tịch HĐQT kiêm Tổng Giám đốc là người đại diện. Các giao dịch này cần được giám sát chặt chẽ để đảm bảo tính công bằng và minh bạch, tránh xung đột lợi ích.', 'Nợ vay ngắn hạn tăng mạnh từ 49 tỷ lên 149,25 tỷ VND (tăng ~204%), dẫn đến chi phí lãi vay tăng từ 1.7 tỷ lên 4.3 tỷ VND (tăng ~149%). Tỷ lệ nợ ngắn hạn/vốn chủ sở hữu đạt ~52.6%. Công ty sử dụng tài sản tài chính FVTPL trị giá 100 tỷ VND làm tài sản thế chấp. Áp lực trả nợ ngắn hạn khá lớn trong khi dòng tiền hoạt động kinh doanh âm (-97.5 tỷ VND).', 'Công ty chứng khoán không có hàng tồn kho vật lý. Rủi ro chính nằm ở các khoản cho vay ký quỹ (150.2 tỷ VND) và ứng trước tiền bán chứng khoán (14.1 tỷ VND), cũng như danh mục đầu tư tài sản tài chính FVTPL (134.9 tỷ VND) chịu rủi ro biến động thị trường.', 6, 'Công ty đã cải thiện kết quả kinh doanh đáng kể: từ lỗ 22.1 tỷ VND năm 2024 sang lãi 6.1 tỷ VND năm 2025, nhờ doanh thu hoạt động tăng 34.5% và tối ưu chi phí. Tuy nhiên, nợ vay ngắn hạn tăng vọt 204%, dòng tiền hoạt động kinh doanh âm mạnh (-97.5 tỷ), và Công ty vẫn đang lỗ lũy kế lớn (-275.3 tỷ VND). Các giao dịch với bên liên quan (công ty mẹ, Finhay Tech) có quy mô lớn cần được giám sát. Công ty có 35.8 tỷ VND lỗ thuế được chuyển sang bù trừ trong 5 năm tới. Triển vọng phụ thuộc vào khả năng quản lý nợ vay và duy trì đà tăng trưởng doanh thu.'),
('VNT_2015_parent', 'VNT', 2015, 'parent', 'Các giao dịch với bên liên quan chủ yếu là giao dịch thương mại bình thường với công ty con. Tuy nhiên, việc ban lãnh đạo dùng tài sản cá nhân thế chấp cho khoản vay của công ty có thể cho thấy sự liên kết lợi ích nhưng cũng tiềm ẩn rủi ro tài chính cá nhân.', 'Công ty có nợ ngắn hạn lớn với lãi suất cao, tạo áp lực thanh toán. Phần lớn nợ không có tài sản bảo đảm hoặc bảo đảm một phần, làm tăng rủi ro thanh khoản.', 'Chi phí xây dựng cơ bản dở dang tăng mạnh, cho thấy dự án đang triển khai. Rủi ro liên quan đến tiến độ và chi phí dự án có thể ảnh hưởng đến dòng tiền.', 4, 'Công ty có lợi nhuận gộp ổn định nhưng biên lợi nhuận thấp. Nợ ngắn hạn cao so với tài sản ngắn hạn, cần theo dõi khả năng thanh toán. Dự án xây dựng đang triển khai có thể mang lại tăng trưởng trong tương lai nhưng cũng rủi ro.'),
('VNSC_2024_consolidated', 'VNSC', 2024, 'consolidated', 'Doanh nghiệp có phát sinh nhiều giao dịch với công ty mẹ (Công ty Cổ phần Finhay Việt Nam), bao gồm chi phí thuê phần mềm trả trước lớn (30.3 tỷ VNĐ), mua bán trái phiếu và chứng chỉ tiền gửi. Các giao dịch này có giá trị lớn, đặc biệt là giao dịch mua bán trái phiếu với công ty mẹ phát sinh lỗ -86.7 tỷ VNĐ. Cần lưu ý rủi ro về giá transfer và tính minh bạch của các giao dịch nội bộ này. Tuy nhiên, thuyết minh có ghi nhận chi tiết mối quan hệ và giá trị.', 'Công ty có khoản vay ngắn hạn 49 tỷ VNĐ từ Ngân hàng TMCP Đầu tư và Phát triển Việt Nam với lãi suất dao động 3-4.3%/năm. Tài sản đảm bảo là trái phiếu chưa niêm yết trị giá 50 tỷ VNĐ. Áp lực nợ vay ngắn hạn tăng cao (từ 0 lên 49 tỷ trong năm 2024), nhưng nợ chỉ chiếm khoảng 14.4% tổng tài sản và được đảm bảo bằng tài sản tài chính thanh khoản cao. Rủi ro thanh khoản có thể quản lý được.', 'Là công ty chứng khoán, không có hàng tồn kho vật lý truyền thống. Rủi ro chính đến từ các tài sản tài chính giao dịch (FVTPL) như trái phiếu, chứng chỉ tiền gửi với giá trị gần 150 tỷ VNĐ. Các tài sản này chịu rủi ro biến động giá thị trường và thanh khoản. Công ty có khoản lỗ đánh giá lại FVTPL trong năm (lỗ chưa thực hiện 976 triệu VNĐ). Dự phòng cho các khoản cho vay khách hàng chưa được trích lập.', 6, 'Công ty đang trong giai đoạn mở rộng mạnh mẽ với số lượng khách hàng tăng nhanh (lên ~107.000), dẫn đến chi phí hoạt động và quản lý tăng vọt, gây lỗ sau thuế -22.1 tỷ VNĐ. Vốn chủ sở hữu đã bị giảm do lỗ lũy kế lớn. Tuy nhiên, Công ty có nền tảng vốn góp lớn (558.6 tỷ VNĐ) và đang tăng cường vay nợ để phục vụ kinh doanh. Triển vọng phụ thuộc vào khả năng tăng doanh thu để bù đắp chi phí trong các năm tới. Rủi ro chính là từ giao dịch với bên liên quan và biến động thị trường tài chính.'),
('VNSC_2023_consolidated', 'VNSC', 2023, 'consolidated', 'Công ty có giao dịch đáng chú ý với Công ty Cổ phần Finhay Việt Nam (bên liên quan qua quan hệ công ty mẹ). Cụ thể, công ty đã trả trước 35.028 tỷ VND tiền thuê phần mềm cho Finhay với hợp đồng thuê 10 năm, trong đó 34.128 tỷ VND vẫn còn cuối kỳ. Đây là giao dịch lớn với bên liên quan duy nhất, tạo rủi ro tập trung đáng kể. Ngoài ra, thù lao cho Tổng Giám đốc Na SungSoo lên tới hơn 2 tỷ VND trong khi công ty vẫn đang trong tình trạng lỗ lũy kế hơn 259 tỷ VND.', 'Công ty không có nợ vay ngân hàng (nợ dài hạn = 0). Tổng nợ phải trả chỉ 3.157 tỷ VND, chủ yếu là phải trả ngắn hạn (phải trả người bán, thuế, lương nhân viên). Tuy nhiên, áp lực tài chính đến từ cam kết thuê phần mềm dài hạn và chi phí trả trước phần mềm lớn (34.446 tỷ VND). Tiền mặt cuối kỳ giảm mạnh từ 120.221 tỷ VND xuống chỉ còn 7.775 tỷ VND, cho thấy thanh khoản bị thu hẹp đáng kể. Công ty có lỗ lũy kế chuyển sang 19.759 tỷ VND chưa được bù trừ thuế.', 'Công ty là công ty chứng khoán, không có hàng tồn kho truyền thống, dự án xây dựng dở dang hay bất động sản đầu tư. Rủi ro tồn kho không áp dụng.', 5, 'Công ty Chứng khoán Vina (VNSC) có vốn điều lệ 558,6 tỷ VND nhưng vốn chủ sở hữu chỉ còn 299,5 tỷ VND do lỗ lũy kế hơn 259 tỷ VND. Năm 2023, doanh thu tăng 40% nhờ đẩy mạnh môi giới chứng khoán trực tuyến, nhưng chi phí hoạt động tăng vọt 1.311% khiến lợi nhuận sau thuế giảm 14% xuống 2,5 tỷ VND. Công ty có cơ cấu tài sản lành mạnh với tỷ lệ nợ/vốn chủ sở hữu rất thấp (~1%), chủ yếu hoạt động bằng vốn tự có. Tuy nhiên, công ty đã trả trước phần mềm 35 tỷ VND cho bên liên quan Finhay trong bối cảnh vẫn lỗ lũy kế lớn, đặt ra câu hỏi về hiệu quả sử dụng vốn. Điểm tích cực là công ty bắt đầu có lãi thực hiện (1,8 tỷ VND) và lợi nhuận chưa thực hiện (692 triệu VND) từ đánh giá lại trái phiếu FVTPL. Triển vọng phụ thuộc vào khả năng kiểm soát chi phí và thu hút khách hàng trong dịch vụ môi giới mới.'),
('VNSC_2020_consolidated', 'VNSC', 2020, 'consolidated', 'Công ty có phát sinh giao dịch tạm ứng quản lý với các thành viên Hội đồng quản trị, Ban kiểm soát và Tổng giám đốc. Các khoản tạm ứng này không có lãi suất và không được đề cập tài sản thế chấp. Mức độ giao dịch không lớn so với tổng tài sản nhưng cần theo dõi tính tuân thủ và minh bạch.', 'Công ty không có nợ vay ngân hàng hay nợ dài hạn tại thời điểm lập báo cáo. Áp lực nợ vay là không có. Tuy nhiên, công ty đang trong tình trạng lỗ lũy kế rất lớn (-234 tỷ VNĐ) làm suy giảm nghiêm trọng vốn chủ sở hữu, đây là rủi ro tài chính cốt lõi.', 'Công ty hoạt động trong lĩnh vực chứng khoán, không có hàng tồn kho vật chất hay dự án bất động sản dở dang. Rủi ro tồn kho là không đáng kể.', 6, 'Công ty Cổ phần Chứng khoán Vina đang trong giai đoạn khó khăn tài chính nghiêm trọng, với khoản lỗ lũy kế lớn (-234.185.014.423 VND) khiến vốn chủ sở hữu thực chất gần như bị xóa sạch so với vốn điều lệ. Lỗ năm 2020 (-69.274.225.459 VND) chủ yếu đến từ hoạt động kinh doanh trái phiếu chưa niêm yết và chi phí quản lý tăng cao. Doanh thu dịch vụ tư vấn, bảo lãnh phát hành có tăng trưởng nhưng không đủ bù đắp. Công ty có thanh khoản ngắn hạn tốt (tiền mặt và tương đương tiền ~18.9 tỷ) nhưng triển vọng kinh doanh và khả năng khắc phục lỗ lũy kế là thách thức lớn. Rủi ro quản trị ở mức trung bình do có giao dịch với bên liên quan và sự thay đổi nhân sự cấp cao.'),
('VNSC_2018_consolidated', 'VNSC', 2018, 'consolidated', 'Công ty thực hiện chuyển nhượng toàn bộ cổ phần từ cổ đông cũ sang cổ đông mới (chủ yếu cá nhân quốc tịch Hàn Quốc) với giá 2,264.59 đồng/cổ phần, thấp hơn mệnh giá 10,000 đồng. Thù lao HĐQT/Ban TGĐ giảm mạnh từ 330 triệu xuống 96 triệu đồng. Công ty không có giao dịch mua bán hàng hóa/dịch vụ bất thường với bên liên quan. Không phát hiện giao dịch cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả ngắn hạn với tổng trị giá ~203.7 triệu VND (thuế, phí dịch vụ, chi phí kiểm toán). Áp lực nợ vay rất thấp. Tuy nhiên, Công ty có lỗ lũy kế lớn (-171.45 tỷ VND) so với vốn điều lệ 185 tỷ, cho thấy quá khứ hoạt động kém hiệu quả.', 'Không áp dụng. Công ty hoạt động trong lĩnh vực tư vấn tài chính và tư vấn đầu tư chứng khoán, không có hàng tồn kho hay dự án xây dựng dở dang.', 4, 'Công ty Cổ phần Chứng khoán Vina là doanh nghiệp quy mô nhỏ (8 nhân viên, vốn điều lệ 185 tỷ đồng). Công ty có lỗ lũy kế lớn (-171.45 tỷ VND) nhưng đã có lãi trở lại trong năm 2018 (lợi nhuận sau thuế 2.77 tỷ VND). Tiền mặt dồi dào (13.95 tỷ VND), không có nợ vay ngân hàng. Năm 2018, toàn bộ cổ phần đã được chuyển nhượng sang cho các nhà đầu tư Hàn Quốc, hứa hẹn thay đổi chiến lược kinh doanh. Tuy nhiên, rủi ro lớn nhất là lỗ lũy kế vẫn chiếm tỷ trọng lớn trong vốn chủ sở hữu và Công ty đã nộp phạt vi phạm hành chính thuế 25.6 triệu VND.'),
('VNSC_2021_consolidated', 'VNSC', 2021, 'consolidated', 'Công ty có giao dịch đáng kể với công ty mẹ (Công ty TNHH DV và PP Finhay Việt Nam) và các cựu cổ đông, bao gồm khoản phải thu lớn từ công ty mẹ và khoản phải trả lớn cho các cổ đông cũ. Điều này tạo rủi ro về khả năng thu hồi khoản phải thu và áp lực nghĩa vụ trả nợ ngắn hạn cho các cổ đông.', 'Công ty không có nợ vay ngân hàng nhưng có khoản phải trả lớn ngắn hạn (129.759.807.750 đồng) phát sinh từ chuyển nhượng cổ phần. Nợ phải trả ngắn hạn vượt quá tài sản ngắn hạn, tạo áp lực thanh khoản nghiêm trọng.', 'Công ty hoạt động trong lĩnh vực chứng khoán, không có hàng tồn kho vật lý nên không có rủi ro tồn kho.', 9, 'Công ty đang trong tình trạng tài chính khó khăn nghiêm trọng với lỗ lũy kế lớn, vốn chủ sở hữu thấp hơn mức quy định, từng bị đặt vào tình trạng kiểm soát đặc biệt. Tuy nhiên, công ty đã có kế hoạch tăng vốn và đảm bảo tỷ lệ an toàn tài chính để hoạt động bình thường năm 2022. Triển vọng phụ thuộc vào khả năng tái cơ cấu và hoạt động kinh doanh hiệu quả.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNSC_2017_consolidated', 'VNSC', 2017, 'consolidated', 'Công ty có giao dịch với các bên liên quan với giá trị lớn, tập trung vào hợp đồng tư vấn tài chính, nhưng không có thông tin cụ thể về giao dịch bất thường.', 'Công ty không có nợ vay, chỉ có nợ phải trả thương mại ngắn hạn, áp lực nợ thấp.', 'Công ty không có hàng tồn kho hoặc dự án xây dựng dở dang, không có rủi ro tồn kho.', 5, 'Công ty có kết quả kinh doanh năm 2017 có lãi, nhưng lỗ lũy kế lớn. Hoạt động kinh doanh chủ yếu dựa vào dịch vụ tư vấn tài chính với các bên liên quan, dòng tiền từ hoạt động kinh doanh dương. Tuy nhiên, công ty có lịch sử thua lỗ và tiềm ẩn rủi ro liên quan đến giao dịch nội bộ.'),
('VNSC_2016_consolidated', 'VNSC', 2016, 'consolidated', 'Giao dịch với bên liên quan trong năm 2016 không phát sinh giá trị, năm 2015 có phát sinh phí môi giới và tư vấn với cổ đông lớn và Chủ tịch Hội đồng Quản trị. Không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay thấp. Nợ phải trả chủ yếu là ngắn hạn (529.563.645 VND trên tổng nợ 557.063.645 VND). Công ty có lượng tiền và tương đương tiền lớn (8.419.068.563 VND), đảm bảo khả năng thanh toán cao. Không có tài sản thế chấp nổi bật cho các khoản nợ.', 'Công ty hoạt động trong lĩnh vực chứng khoán, không có hàng tồn kho (nguyên vật liệu, thành phẩm) hay dự án xây dựng dở dang, do đó không có rủi ro tồn kho.', 3, 'Công ty đang trong tình trạng khó khăn tài chính với lỗ lũy kế lớn (-174.948.014.978 VND) và lỗ sau thuế trong năm 2016 (-2.069.177.457 VND). Hoạt động kinh doanh chính (môi giới, tư vấn) không hiệu quả, doanh thu sụt giảm mạnh so với năm trước. Tuy nhiên, công ty có bảng cân đối kế toán tương đối lành mạnh với lượng tiền mặt dồi dào và nợ phải trả thấp. Triển vọng đầu tư không rõ ràng do kết quả kinh doanh kém và lỗ lũy kế tích lũy.'),
('VNSC_2019_consolidated', 'VNSC', 2019, 'consolidated', 'Công ty có giao dịch cho vay với Hội đồng quản trị với số tiền gốc 4.034.533.100 VND và lãi vay 17.014.260 VND, đã được thu hồi và trả hết trong năm 2019. Thu nhập của HĐQT/BTGĐ tăng đột biến từ 96 triệu VND năm 2018 lên 7,8 tỷ VND năm 2019, cần được lưu ý. Công ty có khoản phải thu bán trái phiếu rất lớn 126,8 tỷ VND với Công ty CP Chứng khoán SmartInvest theo hợp đồng mua bán trái phiếu Công ty TNHH Mặt trời Sông Hàn phát sinh tháng 12/2019, và đồng thời có khoản phải trả người bán lớn 106,4 tỷ VND cho ông Phạm Tài Trường và ông Đoàn Văn Long theo cùng giao dịch mua trái phiếu này, cho thấy hoạt động kinh doanh trái phiếu tập trung với quy mô lớn, có thể tiềm ẩn rủi ro đối tác.', 'Nợ phải trả ngắn hạn chiếm tỷ trọng rất lớn (111,8 tỷ VND), trong đó phải trả người bán ngắn hạn chiếm 106,4 tỷ VND chủ yếu cho các cá nhân liên quan đến giao dịch mua trái phiếu. Công ty có lỗ lũy kế rất lớn 164,9 tỷ VND. Mặc dù Công ty đã tăng vốn chủ sở hữu từ 185 tỷ lên 273,6 tỷ VND trong năm 2019, nhưng lỗ lũy kế vẫn chiếm tỷ trọng đáng kể. Công ty không có nợ vay ngân hàng cuối kỳ (đã vay và trả hết 4 tỷ VND từ HĐQT trong năm).', 'Công ty là công ty chứng khoán, không có hàng tồn kho truyền thống hay dự án xây dựng dở dang. Rủi ro tài sản chủ yếu đến từ danh mục đầu tư chứng khoán tự doanh (FVTPL) với lỗ bán FVTPL 27,5 tỷ VND, đầu tư giữ đến ngày đáo hạn (HTM) 50 tỷ VND tiền gửi có kỳ hạn 6 tháng, và tài sản tài chính sẵn sàng để bán (AFS) 520 triệu VND trái phiếu chưa niêm yết.', 6, 'Công ty CP Chứng khoán Vina đạt lợi nhuận trước thuế 6,5 tỷ VND năm 2019 (tăng 134% so với 2,8 tỷ VND năm 2018), tuy nhiên lợi nhuận chủ yếu đến từ doanh thu hoạt động tài chính 37,3 tỷ VND (chủ yếu lãi trái phiếu 37,2 tỷ VND). Hoạt động kinh doanh chính (tự doanh, tư vấn, môi giới) vẫn lỗ gộp 7,1 tỷ VND do lỗ bán chứng khoán FVTPL 27,5 tỷ VND. Cơ cấu cổ đông thay đổi mạnh trong năm 2019 với nhiều cổ đông mới, tăng vốn từ 185 tỷ lên 273,6 tỷ VND. Công ty có lỗ lũy kế lớn 164,9 tỷ VND và lỗ thuế chuyển từ các năm trước chưa được ghi nhận tài sản thuế hoãn lại. Giao dịch trái phiếu với quy mô lớn (hơn 100 tỷ VND) với các cá nhân trong tháng 12/2019 đặt ra câu hỏi về chất lượng tài sản và rủi ro tập trung.'),
('VNT_2023_consolidated', 'VNT', 2023, 'consolidated', 'Công ty có giao dịch thương mại với các bên liên quan là cổ đông lớn (Vinafreight, Transimex) với tổng giá trị cung cấp dịch vụ 1.78 tỷ VND và mua dịch vụ 507 triệu VND năm 2023. Có phát sinh cho vay lãi suất với các bên liên quan (chi phí lãi vay đã trả cho Vinafreight 1.04 tỷ VND, Transimex 653 triệu VND). Giao dịch với bên liên quan không quá lớn so với quy mô doanh nghiệp nhưng cần theo dõi chặt chẽ.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (223.8 tỷ VND) với lãi suất dao động 4.2%-8.6%/năm. Tổng nợ phải trả (435.1 tỷ VND) chiếm 66.7% tổng tài sản, cho thấy đòn bẩy tài chính cao. Các khoản vay được đảm bảo bằng tiền gửi có kỳ hạn và một số TSCĐ. Áp lực nợ vay ngắn hạn cao, đặc biệt trong bối cảnh công ty đang thua lỗ liên tục.', 'Công ty hoạt động trong lĩnh vực dịch vụ giao nhận vận tải nên không có hàng tồn kho vật chất lớn. Chỉ có chi phí xây dựng cơ bản dở dang 848.9 triệu VND, rủi ro thấp.', 6, 'Công ty đang trong giai đoạn khó khăn với doanh thu giảm 51% (từ 1.803 tỷ xuống 880 tỷ VND) và lỗ sau thuế tăng từ 11.2 tỷ lên 17.6 tỷ VND. Lỗ hợp nhất từ công ty liên kết Cảng Mipec là 31.78 tỷ VND. Nợ vay ngắn hạn lớn, tỷ lệ nợ/tài sản cao. Công ty đã chuyển đổi trái phiếu thành cổ phiếu để giảm áp lực nợ dài hạn. Triển vọng ngắn hạn tiêu cực do ngành vận tải biển và hàng không gặp khó khăn, cước phí giảm sâu.'),
('VNT_2023_parent', 'VNT', 2023, 'parent', 'Công ty có các giao dịch thương mại với công ty con và các nhà đầu tư lớn, nhưng các giao dịch này chủ yếu là cung cấp và mua dịch vụ vận tải, có vẻ dựa trên giá thị trường và không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, mối quan hệ mật thiết với các bên liên quan cần được giám sát để tránh xung đột lợi ích.', 'Nợ vay chủ yếu là ngắn hạn với lãi suất trung bình từ 5.2% đến 8.6%/năm, được đảm bảo bằng tiền gửi có kỳ hạn và tài sản cố định. Áp lực nợ vay ở mức độ vừa phải do công ty có tài sản thế chấp và dòng tiền từ hoạt động kinh doanh, nhưng cần lưu ý về khả năng tái tài trợ khi nợ đáo hạn.', 'Hàng tồn kho không có, chỉ có chi phí xây dựng cơ bản dở dang với giá trị nhỏ, không có rủi ro tồn kho dở dang hoặc dự án xây dựng ứ đọng.', 4, 'Công ty hoạt động trong ngành giao nhận vận tải, doanh thu giảm 46% trong năm 2023 do suy thoái ngành, nhưng vẫn có lợi nhuận sau thuế. Nợ vay giảm, tài sản đầu tư dài hạn tăng, đặc biệt là vào công ty liên kết Cảng Mipec. Dòng tiền từ hoạt động kinh doanh dương, nhưng dòng tiền từ hoạt động tài chính âm do trả nợ gốc. Triển vọng thận trọng do ngành vận tải biển và hàng không còn nhiều thách thức.'),
('VNSC_2015_consolidated', 'VNSC', 2015, 'consolidated', 'Công ty có giao dịch đáng chú ý với bên liên quan. Cổ đông lớn Chu Đặng Ngọc Trinh (nắm giữ 51% vốn) nhận phí tư vấn 2 tỷ VNĐ và phí môi giới 40 triệu VNĐ trong năm 2015 (giảm mạnh so với 7,7 tỷ VNĐ phí tư vấn năm 2014). Tại thời điểm 31/12/2014, Công ty còn phải thu bà Trinh 1,295 tỷ VNĐ. Chủ tịch Horst Joachim Franz Geicke cũng phát sinh phí môi giới 8,9 triệu VNĐ. Các giao dịch này không có thông tin về cơ sở giá thị trường, tiềm ẩn rủi ro xung đột lợi ích và chuyển giá giữa công ty và cổ đông chi phối.', 'Công ty không có nợ vay ngân hàng, tổng nợ phải trả chỉ khoảng 1,79 tỷ VNĐ (chủ yếu là phải trả ngắn hạn). Tuy nhiên, áp lực tài chính lớn đến từ việc lỗ lũy kế lên đến 172,9 tỷ VNĐ (gần bằng toàn bộ vốn điều lệ 185 tỷ VNĐ), dòng tiền hoạt động kinh doanh âm 5,4 tỷ VNĐ. Tiền mặt giảm từ 16 tỷ xuống 10,5 tỷ VNĐ trong năm. Công ty đang trong giai đoạn thu hẹp hoạt động kinh doanh, rút giấy phép môi giới và lưu ký chứng khoán.', 'Là công ty chứng khoán, Công ty không có hàng tồn kho truyền thống. Chi phí xây dựng cơ bản dở dang đã hoàn thành/bàn giao trong năm (từ 353 triệu về 0 VNĐ). Không có rủi ro tồn kho đáng kể.', 7, 'Công ty CPCK Vina đang trong tình trạng tài chính nghiêm trọng. Lỗ lũy kế 172,9 tỷ VNĐ chiếm 93,5% vốn điều lệ, chỉ còn vốn chủ sở hữu 12,4 tỷ VNĐ. Doanh thu giảm 51% (từ 17,8 tỷ xuống 8,7 tỷ VNĐ), lỗ gộp 545 triệu VNĐ và lỗ sau thuế 5,58 tỷ VNĐ. Công ty đã rút hoạt động môi giới và lưu ký chứng khoán - hai nghiệp vụ chủ lực, chỉ còn 7 nhân viên (từ 22 người). Giao dịch phí tư vấn lớn với cổ đông chi phối 51% đặt ra câu hỏi về quản trị. Tổng lỗ thuế chưa quyết toán có thể mang sang bù trừ lên đến 46,7 tỷ VNĐ nhưng không ghi nhận tài sản thuế hoãn lại. Triển vọng đầu tư rất kém, rủi ro cao về khả năng duy trì hoạt động trong dài hạn.'),
('VNS_2025_consolidated', 'VNS', 2025, 'consolidated', 'Có giao dịch đáng chú ý với các bên liên quan, chủ yếu là thanh toán cổ tức lớn cho các cổ đông lớn (bao gồm cá nhân và tổ chức có quan hệ) và giao dịch mua dịch vụ, chia lợi nhuận với công ty liên quan đến lãnh đạo (Xưởng sửa chữa ô tô Thành Lợi). Giá trị giao dịch lớn, cần đánh giá tính công bằng và thị trường.', 'Áp lực nợ vay tương đối cao với tổng nợ vay và nợ thuê tài chính gần 500 tỷ VNĐ. Công ty có tài sản thế chấp lớn (phương tiện vận tải) cho các khoản vay. Đặc biệt có ghi nhận vi phạm điều khoản vay với HSBC (hệ số hoàn trả nợ vay thấp hơn yêu cầu) nhưng công ty đánh giá là tạm thời.', 'Rủi ro tồn kho thấp. Hàng tồn kho chủ yếu là phụ tùng ô tô, giá trị tăng nhẹ so với đầu năm, dự phòng giảm giá không được thuyết minh chi tiết trong phần này.', 6, 'Công ty hoạt động trong ngành vận tải taxi, có doanh thu sụt giảm nhưng lợi nhuận gộp vẫn dương. Cơ cấu tài sản chủ yếu là tài sản cố định (phương tiện vận tải) được tài trợ bởi nợ vay dài hạn. Dòng tiền từ hoạt động kinh doanh mạnh. Điểm rủi ro cao đến từ giao dịch với bên liên quan và áp lực nợ vay, đặc biệt là vi phạm điều khoản tài chính. Năng lực sinh lời có xu hướng giảm (lợi nhuận sau thuế giảm mạnh so với năm trước) và có lỗ lũy kế lớn có thể bù trừ thuế.'),
('VNS_2024_consolidated', 'VNS', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là chi trả cổ tức cho cổ đông lớn và ban lãnh đạo, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay tăng mạnh từ 289,6 tỷ lên 553,7 tỷ VNĐ, chủ yếu là vay ngân hàng mua phương tiện vận tải. Tài sản thế chấp là xe. Công ty có dòng tiền hoạt động kinh doanh dương nhưng áp lực trả nợ tăng.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô với giá trị nhỏ và ổn định, rủi ro thấp.', 4, 'Doanh thu và lợi nhuận giảm so với năm trước do ảnh hưởng của ngành vận tải taxi. Nợ vay tăng cao để đầu tư xe mới. Công ty vẫn duy trì chi trả cổ tức. Triển vọng phụ thuộc vào sự phục hồi của ngành du lịch và vận tải.'),
('VNS_2023_consolidated', 'VNS', 2023, 'consolidated', 'Giao dịch với công ty con (ADX) và thù lao cho ban lãnh đạo được ghi nhận. Không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan được đề cập rõ ràng.', 'Tổng nợ vay và nợ thuê tài chính tăng từ 243 tỷ lên 290 tỷ VND, tập trung vào vay mua xe. Áp lực trả nợ ngắn hạn lớn (khoảng 96 tỷ). Tài sản thế chấp chủ yếu là xe ô tô (khoảng 399 xe) và tiền gửi.', 'Tồn kho chính là phụ tùng ô tô với giá trị không lớn và có xu hướng giảm nhẹ. Dự án xây dựng cơ bản dở dang là phương tiện vận tải, rủi ro thấp do liên quan trực tiếp đến hoạt động kinh doanh cốt lõi.', 4, 'Sức khỏe tài chính ổn định với tăng trưởng doanh thu 11.9% nhưng lợi nhuận giảm 18%. Công ty có cấu trúc tài chính đòn bẩy cao với nợ vay tăng mạnh để tài trợ mua sắm tài sản. Lợi thế là dòng tiền kinh doanh mạnh (317 tỷ) và tỷ suất lợi nhuận gộp ổn định (~21%). Rủi ro chính nằm ở áp lực nợ vay ngắn hạn và biến động lãi suất.'),
('VNS_2024_parent', 'VNS', 2024, 'parent', 'Các giao dịch với bên liên quan chủ yếu là thanh toán cổ tức và chi phí trả hộ cho công ty con, không có dấu hiệu bất thường hay giao dịch giá trị không hợp lý.', 'Công ty có nợ vay và nợ thuê tài chính đáng kể với tổng cộng khoảng 538 tỷ VNĐ, chủ yếu để mua phương tiện vận tải. Lãi suất biến động theo lãi suất cơ sở và tài sản thế chấp là xe taxi. Áp lực trả nợ ngắn hạn cao nhưng dòng tiền từ hoạt động kinh doanh vẫn dương.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô, giá trị tương đối thấp và không có dự phòng giảm giá. Rủi ro tồn kho thấp do tính chất tiêu hao và không có dự án xây dựng dở dang.', 5, 'Công ty hoạt động trong lĩnh vực vận tải taxi, du lịch và cho thuê mặt bằng. Doanh thu giảm so với năm trước nhưng vẫn có lợi nhuận. Nợ vay tăng để mở rộng đội xe, song công ty có dòng tiền hoạt động kinh doanh ổn định. Quản trị công ty minh bạch với các giao dịch bên liên quan được công bố, nhưng cần theo dõi áp lực trả nợ và lợi nhuận gộp giảm.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNS_2025_parent', 'VNS', 2025, 'parent', 'Các giao dịch với bên liên quan bao gồm chi phí trả hộ, mua dịch vụ, chi phí phần mềm và thanh toán cổ tức, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Giao dịch chủ yếu với công ty con và cổ đông lớn, rủi ro thấp.', 'Công ty có nợ vay ngân hàng và nợ thuê tài chính, được thế chấp bằng xe ô tô. Lãi suất biến động theo lãi suất cơ sở. Tại ngày 31/12/2025, vi phạm chỉ tiêu tài chính với HSBC nhưng đánh giá là tạm thời. Tổng nợ giảm so với đầu năm, nhưng chi phí lãi vay tăng, cho thấy áp lực nợ vay ở mức trung bình.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô, không có dự án xây dựng dở dang. Giá trị tồn kho ổn định, không có dấu hiệu ứ đọng, rủi ro thấp.', 4, 'Công ty hoạt động trong lĩnh vực vận tải hành khách bằng taxi, doanh thu giảm so với năm trước nhưng lợi nhuận gộp cải thiện. Dòng tiền từ hoạt động kinh doanh mạnh, nhưng lợi nhuận sau thuế giảm do chi phí tài chính và thuế tăng. Công ty có cơ cấu tài sản vững chắc với tài sản cố định lớn, nhưng nợ vay vẫn ở mức cao. Tổng thể, tình hình tài chính ổn định, triển vọng trung bình.'),
('VNS_2023_parent', 'VNS', 2023, 'parent', 'Công ty có giao dịch với công ty con Công ty Cổ phần Ánh Dương Xanh Việt Nam (99% sở hữu) chủ yếu bao gồm chi phí trả hộ và tiền trả trước liên quan đến sử dụng thể taxi. Giá trị giao dịch không quá lớn so với quy mô hoạt động và có vẻ là giao dịch kinh doanh thông thường trong ngành vận tải taxi. Không phát hiện giao dịch bất thường đáng kể.', 'Tổng nợ vay và thuê tài chính đạt 274,16 tỷ VND (tăng 17% so với năm trước), trong đó nợ dài hạn chiếm tỷ trọng lớn. Công ty sử dụng tài sản thế chấp là xe taxi (507 xe cho vay ngân hàng) và phương tiện vận tải thuê tài chính. Áp lực trả nợ ở mức trung bình, với dòng tiền hoạt động kinh doanh mạnh (305,7 tỷ VND) có thể bù đắp được nghĩa vụ nợ.', 'Hàng tồn kho ở mức thấp (5,65 tỷ VND), chủ yếu là phụ tùng ô tô phục vụ sửa chữa xe taxi. Dự án xây dựng cơ bản dở dang trị giá 4,6 tỷ VND là xe vận tải đang trong quá trình hoàn thiện. Rủi ro tồn kho thấp do tính chất luân chuyển nhanh trong ngành dịch vụ vận tải.', 3, 'Công ty Cổ phần Ánh Dương Việt Nam là đơn vị vận tải taxi hàng đầu tại TP.HCM với doanh thu thuần tăng 12,2% so với năm trước. Lợi nhuận sau thuế đạt 142,4 tỷ VND (giảm 16% do chi phí tài chính tăng mạnh). Dòng tiền hoạt động kinh doanh dương mạnh (305,7 tỷ VND) phản ánh năng lực tạo tiền tốt. Công ty đang mở rộng đầu tư vào công ty con (tăng tỷ lệ sở hữu từ 90% lên 99%). Điểm cần lưu ý là khoản lỗ thuế chuyển sang từ năm 2021 (81,1 tỷ VND) có thể ảnh hưởng đến nghĩa vụ thuế trong tương lai. Cổ tức tiền mặt được chi trả cao (359,6 tỷ VND) cho thấy chính sách trả cổ tức hào phóng.'),
('VNS_2022_parent', 'VNS', 2022, 'parent', 'Công ty có giao dịch đáng kể với công ty con là Công ty Cổ phần Ánh Dương Xanh Việt Nam, bao gồm thanh lý xe, chi phí trả hộ và tiền trả trước liên quan đến sử dụng thể taxi. Các giao dịch này có thể tiềm ẩn rủi ro về giá transfer và tính minh bạch nếu không được quản lý chặt chẽ.', 'Tổng nợ vay và nợ thuê tài chính là 234.406.964.784 VND. Công ty đã tăng cường vay dài hạn để mua sắm tài sản, với tài sản thế chấp chủ yếu là xe ô tô. Áp lực trả nợ tập trung vào nợ thuê tài chính ngắn hạn đến hạn trả. Công ty có dòng tiền kinh doanh mạnh (326.556.581.203 VND) hỗ trợ khả năng trả nợ.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô với giá trị tương đối nhỏ (5.806.385.701 VND), không có dự án xây dựng dở dang hay bất động sản tồn đọng. Rủi ro tồn kho thấp.', 5, 'Công ty đã có sự phục hồi mạnh mẽ về lợi nhuận sau thuế (169.557.792.271 VND) so với năm trước lỗ, nhờ doanh thu tăng mạnh và kiểm soát chi phí. Tuy nhiên, công ty vẫn còn khoản lỗ thuế lũy kế lớn (229.481.814.445 VND) có thể bù trừ trong tương lai. Nợ vay tăng đáng kể để tài trợ cho hoạt động kinh doanh, nhưng dòng tiền hoạt động kinh doanh mạnh tạo đệm an toàn. Giao dịch với bên liên quan (công ty con) cần được giám sát để đảm bảo tính công bằng.'),
('VNS_2022_consolidated', 'VNS', 2022, 'consolidated', 'Danh sách bên liên quan bao gồm nhiều cá nhân là thành viên HĐQT, Ban Tổng Giám đốc và các công ty có liên quan đến Chủ tịch HĐQT. Các giao dịch chính bao gồm tiền lương, thưởng và ký quỹ. Mặc dù không có bằng chứng rõ ràng về giao dịch bất thường, việc có nhiều bên liên quan là cá nhân trong Ban lãnh đạo đòi hỏi sự giám sát chặt chẽ về mặt quản trị.', 'Công ty có cơ cấu nợ đáng kể với tổng nợ vay và nợ thuê tài chính là 243,465,142,700 VND, tăng mạnh so với năm trước. Nợ chủ yếu phục vụ cho việc mua sắm phương tiện vận tải (xe taxi) và được thế chấp bằng chính tài sản này. Áp lực trả nợ trong ngắn hạn (81,287,007,580 VND) là tương đối lớn so với tiền mặt và tương đương tiền (196,769,080,578 VND). Công ty có sử dụng đòn bẩy tài chính cao.', 'Rủi ro hàng tồn kho thấp. Hàng tồn kho chủ yếu là phụ tùng ô tô với giá trị không lớn (8.7 tỷ VND) và không có dự phòng giảm giá. Không có hàng tồn kho dở dang hay dự án xây dựng dở dang.', 6, 'Công ty đã có sự phục hồi mạnh mẽ trong năm 2022 sau khoản lỗ lớn năm 2021, đạt lợi nhuận sau thuế 185,350,736,288 VND. Doanh thu tăng trưởng tốt, đặc biệt từ mảng kinh doanh cốt lõi là vận tải hành khách bằng taxi. Tuy nhiên, công ty gia tăng mạnh nợ vay để mở rộng đội xe, làm tăng rủi ro tài chính. Cơ cấu quản trị có sự hiện diện của nhiều thành viên gia đình Chủ tịch HĐQT, cần được theo dõi. Triển vọng kinh doanh tích cực nhưng phụ thuộc vào việc kiểm soát chi phí và quản lý hiệu quả đòn bẩy tài chính.'),
('VNS_2019_consolidated', 'VNS', 2019, 'consolidated', 'Công ty không có giao dịch bất thường với các bên liên quan ngoài thù lao của Hội đồng Quản trị và Ban Giám đốc. Các giao dịch với các bên liên quan được ghi nhận và công khai trong báo cáo, không có dấu hiệu cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Công ty có tổng nợ vay và nợ thuê tài chính lớn, lên đến hơn 571 tỷ VNĐ. Các khoản vay dài hạn chủ yếu được đảm bảo bằng tài sản thế chấp là xe ô tô. Lãi suất biến động theo lãi suất cơ bản. Áp lực trả nợ trong ngắn hạn (gần 252 tỷ) là đáng kể, tuy nhiên dòng tiền từ hoạt động kinh doanh mạnh (hơn 483 tỷ) hỗ trợ khả năng thanh toán.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô, giá trị giảm so với đầu năm. Dự án xây dựng cơ bản dở dang tăng mạnh (từ 100 triệu lên hơn 120 tỷ) liên quan đến việc chuẩn bị xe cho dịch vụ taxi. Rủi ro tồn kho không cao do tính chất dự án rõ ràng.', 4, 'Công ty ghi nhận sự cải thiện rõ rệt về lợi nhuận sau thuế (tăng 20%) nhờ giảm chi phí tài chính và tăng thu nhập khác từ thanh lý tài sản. Dòng tiền hoạt động kinh doanh rất mạnh và ổn định. Tuy nhiên, công ty đang trong quá trình cơ cấu tài sản, bán bớt xe cũ (doanh thu từ thanh lý lớn) và đầu tư mới. Nợ vay vẫn ở mức cao nhưng được kiểm soát bằng tài sản thế chấp và dòng tiền. Hội đồng Quản trị có sự thay đổi thành viên trong năm. Nhìn chung, công ty có sức khỏe tài chính ổn định và triển vọng kinh doanh tích cực trong lĩnh vực vận tải taxi truyền thống.'),
('VNS_2021_consolidated', 'VNS', 2021, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là thù lao cho thành viên Hội đồng Quản trị và Ban Tổng Giám đốc. Không ghi nhận giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, nhiều vị trí lãnh đạo chủ chốt thuộc cùng gia tộc (họ Đăng), tiềm ẩn rủi ro về quản trị và xung đột lợi ích.', 'Tổng nợ vay và nợ thuê tài chính giảm mạnh từ 342 tỷ xuống 188 tỷ VND trong năm, cho thấy công ty đã tích cực trả nợ. Nợ ngắn hạn chiếm phần lớn (130 tỷ), áp lực thanh toán ngắn hạn vẫn tồn tại. Tài sản thế chấp chủ yếu là xe ô tô kinh doanh.', 'Hàng tồn kho chỉ gồm phụ tùng ô tô với giá trị 9.1 tỷ VND, giảm so với năm trước. Không có dự án bất động sản hay xây dựng dở dang. Rủi ro tồn kho thấp do tính thanh khoản của phụ tùng.', 6, 'Công ty chịu ảnh hưởng nặng nề từ đại dịch COVID-19 với doanh thu giảm 51.5% và lỗ gộp tăng lên. Tuy nhiên, công ty đã chủ động giảm nợ vay và cải thiện dòng tiền hoạt động. Triển vọng phụ thuộc vào sự phục hồi của ngành vận tải hành khách và du lịch. Tình hình tài chính còn nhiều thách thức với khoản lỗ lũy kế lớn.'),
('VNS_2019_parent', 'VNS', 2019, 'parent', 'Rủi ro liên quan đến giao dịch với bên liên quan ở mức thấp. Giao dịch chủ yếu là chi phí trả hộ cho công ty con (Công ty Cổ phần Ánh Dương Xanh Việt Nam) với giá trị ghi nhận trong năm là 10.777 tỷ VND, không có dấu hiệu giao dịch bất thường hay ưu đãi đáng ngờ.', 'Áp lực nợ vay ở mức trung bình. Tổng nợ vay và nợ thuê tài chính cuối kỳ là 500.608 tỷ VND, trong đó nợ dài hạn là 443.550 tỷ VND. Các khoản vay ngân hàng dài hạn chủ yếu để mua xe taxi, được thế chấp bằng chính phương tiện vận tải (xe). Lãi suất biến động theo lãi suất cơ sở/cơ bản của ngân hàng cộng biên độ. Công ty có dòng tiền hoạt động kinh doanh mạnh (437.825 tỷ VND) để trang trải các khoản thanh toán.', 'Rủi ro tồn kho thấp. Hàng tồn kho chủ yếu là phụ tùng ô tô với giá trị giảm từ 15.702 tỷ VND đầu năm xuống 11.729 tỷ VND cuối kỳ, cho thấy khả năng quản lý tồn kho hiệu quả. Dự án xây dựng dở dang (120.046 tỷ VND) là phương tiện đang lắp ráp, không có dấu hiệu ứ đọng lâu dài.', 5, 'Công ty Cổ phần Ánh Dương Việt Nam là doanh nghiệp taxi lớn, có tình hình tài chính tương đối ổn định. Doanh thu thuần giảm nhẹ nhưng lợi nhuận gộp và lợi nhuận sau thuế tăng trưởng. Dòng tiền hoạt động kinh doanh dương mạnh cho thấy khả năng tạo tiền tốt. Nợ vay lớn nhưng chủ yếu phục vụ hoạt động kinh doanh cốt lõi và có tài sản thế chấp rõ ràng. Các giao dịch với bên liên quan không đáng kể. Rủi ro quản trị ở mức trung bình do ban lãnh đạo có biến động trong năm (bổ nhiệm và miễn nhiệm một số thành viên). Triển vọng đầu tư phụ thuộc vào sự phục hồi của ngành vận tải và du lịch.'),
('VNS_2020_consolidated', 'VNS', 2020, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao trả cho các thành viên Hội đồng Quản trị và Ban Tổng Giám đốc (4,554 triệu VND). Không phát hiện giao dịch bất thường, cho vay không lãi suất hay mua bán chênh lệch lớn với bên liên quan.', 'Công ty có tổng nợ vay và thuê tài chính 342 tỷ VND, giảm mạnh so với năm trước (572 tỷ VND). Phần lớn nợ được đảm bảo bằng xe ô tô. Áp lực trả nợ gốc trong năm tới là đáng kể với hơn 172 tỷ VND nợ ngắn hạn. Công ty đã chủ động giảm đòn bẩy tài chính trong năm lỗ.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô với giá trị giảm so với đầu năm (từ 15,7 tỷ xuống 13 tỷ VND). Rủi ro tồn kho thấp do tính chất kinh doanh dịch vụ và không có bất động sản đầu tư hay hàng tồn kho dở dang xây dựng.', 4, 'Công ty chịu ảnh hưởng nặng nề từ đại dịch Covid-19 trong năm 2020, dẫn đến khoản lỗ ròng 207 tỷ VND. Tuy nhiên, dòng tiền hoạt động kinh doanh vẫn dương 109 tỷ VND. Công ty đã tích cực bán tài sản cố định (thu 222 tỷ VND) để cải thiện thanh khoản và giảm mạnh nợ vay. Sức khỏe tài chính bị suy yếu do lỗ lũy kế giảm vốn chủ sở hữu, nhưng công ty đã có những bước đi chủ động trong tái cơ cấu nợ và tài sản.'),
('VNS_2021_parent', 'VNS', 2021, 'parent', 'Giao dịch với công ty con liên quan đến tiền trả trước sử dụng thể taxi và chi phí trả hộ, không có dấu hiệu bất thường về giá hoặc lãi suất.', 'Công ty có mức nợ vay cao với lãi suất biến động và tài sản thế chấp là xe ô tô. Áp lực nợ vay đáng kể do công ty đang thua lỗ trong năm 2021.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô, giá trị thấp và không có dự phòng giảm giá, rủi ro thấp.', 4, 'Công ty Cổ phần Ánh Dương Việt Nam đang đối mặt với khó khăn tài chính với lỗ kế toán lớn trong năm 2021 và nợ vay cao. Tuy nhiên, công ty có tài sản cố định lớn và dòng tiền từ thanh lý tài sản. Triển vọng phụ thuộc vào sự phục hồi của ngành vận tải sau đại dịch COVID-19 và quản lý nợ hiệu quả.'),
('VNS_2020_parent', 'VNS', 2020, 'parent', 'Giao dịch với công ty con (ADX) bao gồm tiền trả trước cho việc sử dụng thẻ taxi và chi phí trả hộ. Giá trị giao dịch tăng mạnh so với năm trước. Không có giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn rõ ràng được đề cập.', 'Công ty có khoản nợ vay và thuê tài chính lớn (tổng cộng ~296,6 tỷ VNĐ), giảm mạnh so với đầu năm (~500,6 tỷ VNĐ). Phần lớn nợ được đảm bảo bằng xe ô tô (phương tiện vận tải). Áp lực nợ vay vẫn hiện hữu khi công ty đang trong giai đoạn khó khăn, nhưng việc trả nợ trong năm cho thấy nỗ lực giảm đòn bẩy.', 'Hàng tồn kho chủ yếu là phụ tùng ô tô, giá trị không lớn và đã giảm so với năm trước, không có dự phòng giảm giá. Rủi ro tồn kho thấp.', 4, 'Năm 2020 là một năm khó khăn nghiêm trọng đối với Ánh Dương Việt Nam (VNS) do ảnh hưởng của đại dịch Covid-19, thể hiện qua khoản lỗ ròng lớn (~175 tỷ VNĐ). Công ty đã tích cực tái cơ cấu tài chính bằng cách trả nợ vay và thuê tài chính, giảm mạnh nợ phải trả. Doanh thu sụt giảm mạnh trong khi giá vốn vẫn cao dẫn đến lỗ gộp. Công ty cần khôi phục hoạt động kinh doanh cốt lõi (taxi, vận tải) để cải thiện dòng tiền và lợi nhuận.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNS_2017_consolidated', 'VNS', 2017, 'consolidated', 'Không có giao dịch bên liên quan đáng kể được trình bày trong báo cáo, rủi ro thấp.', 'Công ty có nợ vay dài hạn lớn với các ngân hàng, chủ yếu thế chấp bằng xe taxi. Áp lực nợ vay có thể cao do lợi nhuận giảm mạnh trong năm.', 'Hàng tồn kho chủ yếu là công cụ, dụng cụ, rủi ro thấp. Dự án xây dựng dở dang nhỏ, không đáng lo ngại.', 3, 'Công ty có doanh thu giảm mạnh trong năm 2017, lợi nhuận sau thuế giảm. Nợ vay cao nhưng tài sản cố định lớn. Công ty đang chuyển đổi mô hình kinh doanh sang nhượng quyền thương mại, triển vọng phụ thuộc vào hoạt động kinh doanh taxi và nhượng quyền.'),
('VNS_2018_parent', 'VNS', 2018, 'parent', 'Các giao dịch với bên liên quan chủ yếu là thù lao cho ban lãnh đạo (5.1 tỷ VND), mức này hợp lý so với quy mô doanh nghiệp. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Tổng nợ vay (ngắn và dài hạn) xấp xỉ 708 tỷ VND, trong đó phần lớn là vay dài hạn được thế chấp bằng xe ô tô (tài sản cố định). Công ty có các khoản vay lớn từ nhiều ngân hàng quốc tế và trong nước với lãi suất biến động theo thị trường. Áp lực nợ vay tồn tại, đặc biệt là các khoản nợ đến hạn trả trong ngắn hạn (khoảng 348 tỷ VND).', 'Hàng tồn kho (phụ tùng ô tô) có giá trị ~19.4 tỷ VND, chiếm tỷ trọng nhỏ trong tổng tài sản. Rủi ro tồn kho thấp, chủ yếu phục vụ cho hoạt động sửa chữa, bảo dưỡng xe.', 3, 'Công ty hoạt động trong lĩnh vực vận tải taxi truyền thống, chịu ảnh hưởng mạnh từ dịch vụ gọi xe công nghệ, thể hiện qua sự sụt giảm mạnh doanh thu thuần (-29.4%). Lợi nhuận giảm chủ yếu do hoạt động kinh doanh cốt lõi suy giảm, nhưng được bù đắp một phần bởi lợi nhuận lớn từ hoạt động thanh lý tài sản cố định (~48.5 tỷ VND). Công ty có cơ cấu tài sản dài hạn lớn (xe ô tô) và nợ vay tương ứng. Dòng tiền từ hoạt động kinh doanh vẫn dương và mạnh, cho thấy khả năng tạo tiền tốt. Tuy nhiên, cần theo dõi khả năng tái cơ cấu hoạt động kinh doanh để thích ứng với môi trường cạnh tranh mới và quản lý hiệu quả gánh nặng nợ vay.'),
('VNS_2018_consolidated', 'VNS', 2018, 'consolidated', 'Giao dịch bên liên quan chủ yếu là lương và thưởng cho Ban Tổng Giám đốc và Hội đồng Quản trị, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Doanh nghiệp có nợ vay lớn chủ yếu từ ngân hàng và thuê tài chính, được đảm bảo bằng tài sản xe cộ. Lãi suất dao động, áp lực nợ vay trung bình nhưng khả năng thanh toán được hỗ trợ bởi dòng tiền kinh doanh ổn định.', 'Hàng tồn kho là phụ tùng ô tô với giá trị thấp, không có dự án xây dựng dở dang, rủi ro tồn kho thấp.', 2, 'Công ty hoạt động trong ngành vận tải taxi, doanh thu và lợi nhuận năm 2018 giảm so với năm trước. Nợ vay được quản lý thận trọng với tài sản thế chấp, dòng tiền hoạt động kinh doanh dương. Tình hình tài chinh trung bình, triển vọng phụ thuộc vào diễn biến thị trường vận tải.'),
('VNS_2016_consolidated', 'VNS', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao cho Hội đồng Quản trị và Ban Giám đốc, không có thông tin về giao dịch mua bán, vay mượn bất thường hay công ty con, công ty liên doanh liên kết phức tạp đáng lo ngại.', 'Công ty có nợ vay và nợ thuê tài chính dài hạn lớn,主要用于 mua sắm tài sản cố định (xe taxi). Các khoản vay có tài sản thế chấp là chính phương tiện vận tải. Áp lực trả nợ gốc tập trung trong năm 2017. Công ty có dòng tiền hoạt động kinh doanh dương mạnh có khả năng hỗ trợ nghĩa vụ nợ.', 'Hàng tồn kho chủ yếu là công cụ, dụng cụ và giá trị không lớn, không có dự án xây dựng dở dang phức tạp. Rủi ro tồn kho thấp.', 4, 'Công ty hoạt động ổn định trong ngành vận tải taxi. Năng lực sinh lời tốt (doanh thu hơn 4.500 tỷ, lợi nhuận trước thuế ~397 tỷ). Dòng tiền từ hoạt động kinh doanh mạnh (~593 tỷ) đủ để trang trải chi phí đầu tư lớn. Nợ vay lớn nhưng có mục đích rõ ràng và được đảm bảo bằng tài sản. Điểm rủi ro chính là áp lực trả nợ tập trung trong ngắn hạn và chi phí lãi vay tăng. Tổng thể, sức khỏe tài chính ở mức trung bình khá.'),
('VNS_2017_parent', 'VNS', 2017, 'parent', 'Giao dịch với bên liên quan chủ yếu là chi phí trả hộ cho công ty con, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay dài hạn lớn nhưng đang giảm dần. Áp lực nợ ngắn hạn cao với 370 tỷ VNĐ đến hạn trả trong năm 2018. Tài sản thế chấp chủ yếu là xe vận tải, giúp giảm rủi ro tín dụng.', 'Hàng tồn kho là công cụ, dụng cụ với giá trị nhỏ, rủi ro thấp. Chi phí xây dựng cơ bản dở dang giảm mạnh, cho thấy các dự án có thể đã hoàn thành, không bị ứ đọng.', 3, 'Công ty có tình hình tài cơ bản ổn định, nhưng doanh thu giảm mạnh do thay đổi mô hình kinh doanh sang nhượng quyền. Lợi nhuận gộp giảm, nhưng dòng tiền từ hoạt động kinh doanh vẫn dương. Nợ vay được kiểm soát, với việc thanh toán nợ gốc đáng kể trong năm. Triển vọng phụ thuộc vào sự phục hồi doanh thu từ dịch vụ nhượng quyền taxi.'),
('VNS_2015_consolidated', 'VNS', 2015, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là thù lao lương thưởng cho ban lãnh đạo, không phát hiện giao dịch bất thường lớn như cho vay không lãi suất hay mua bán chênh lệch.', 'Nợ vay dài hạn và ngắn hạn lớn, với lãi suất biến động và tài sản thế chấp là xe taxi, tạo áp lực trả nợ và chi phí lãi vay cao.', 'Hàng tồn kho thấp, chủ yếu là công cụ dụng cụ; dự án xây dựng dở dang là mua sắm phương tiện vận tải, rủi ro không cao.', 3, 'Doanh nghiệp có doanh thu và lợi nhuận tăng trưởng ổn định, nhưng nợ vay tăng cao dẫn đến chi phí tài chính lớn. Sức khỏe tài chính trung bình, cần giám sát quản lý nợ và dòng tiền.'),
('VNS_2016_parent', 'VNS', 2016, 'parent', 'Giao dịch với công ty con (Công ty Cổ phần Ánh Dương Xanh Việt Nam) chỉ giới hạn ở chi phí trả hộ, không có giao dịch mua bán hàng hóa hay cho vay không lãi suất bất thường. Số dư phải trả cho công ty con cuối năm là 4 tỷ VNĐ, mức độ ảnh hưởng không đáng kể.', 'Áp lực nợ vay lớn với tổng nợ vay và nợ thuê tài chính trên 1.126 tỷ VNĐ, trong đó nợ ngắn hạn đến hạn trả trong năm 2017 là 412 tỷ VNĐ. Tuy nhiên, tài sản đảm bảo chủ yếu là xe taxi (hơn 3.700 xe) và công ty có dòng tiền hoạt động kinh doanh mạnh (564 tỷ VNĐ trong năm) có thể hỗ trợ thanh toán. Lãi suất vay biến động theo lãi suất cơ bản và biên độ.', 'Hàng tồn kho chủ yếu là công cụ, dụng cụ (10,5 tỷ VNĐ) và chi phí xây dựng cơ bản dở dang (24 tỷ VNĐ) chiếm tỷ trọng nhỏ trong tổng tài sản, không có dấu hiệu ứ đọng hay dự phòng giảm giá lớn.', 3, 'Công ty hoạt động trong lĩnh vực vận tải taxi truyền thống với doanh thu ổn định nhưng lợi nhuận giảm nhẹ do chi phí tăng. Cơ cấu tài trợ chủ yếu bằng nợ vay để mua xe taxi, tạo đòn bẩy tài chính cao nhưng được hỗ trợ bởi tài sản đảm bảo lớn và dòng tiền kinh doanh tích cực. Rủi ro quản trị ở mức thấp, không có giao dịch bên liên quan phức tạp.'),
('VNS_2015_parent', 'VNS', 2015, 'parent', 'Giao dịch với bên liên quan chủ yếu là công ty con, quy mô nhỏ, không có dấu hiệu bất thường.', 'Công ty có nợ vay dài hạn lớn, chiếm tỷ trọng cao trong tổng tài sản, áp lực lãi vay và trả nợ gốc đáng kể.', 'Hàng tồn kho chủ yếu là công cụ, dụng cụ, giá trị thấp; dự án xây dựng dở dang và bất động sản đầu tư không có dấu hiệu ứ đọng.', 3, 'Công ty hoạt động trong lĩnh vực vận tải taxi, doanh thu tăng trưởng ổn định, lợi nhuận tăng nhưng nợ vay cao để tài trợ mở rộng. Sức khỏe tài chính trung bình, cần theo dõi khả năng thanh toán nợ.'),
('VNR_2025_parent', 'VNR', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm cổ đông lớn, công ty con, công ty liên kết và công ty có cùng nhân sự chủ chốt. Các giao dịch chủ yếu liên quan đến nghiệp vụ tái bảo hiểm, hoa hồng, bồi thường và cổ tức. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn, nhưng cần theo dõi do tần suất giao dịch cao.', 'Công ty không có vay nợ ngân hàng, nợ phải trả chủ yếu là phải trả về hợp đồng bảo hiểm và dự phòng nghiệp vụ. Áp lực nợ vay thấp, khả năng thanh toán tốt với biên khả năng thanh toán cao. Tài sản thế chấp không đáng kể.', 'Hàng tồn kho giá trị nhỏ, không có rủi ro tồn kho lớn. Dự án bất động sản Tincom Plaza đã trích lập dự phòng 100%, rủi ro đã được xử lý. Không có dự án xây dựng dở dang.', 3, 'Tổng Công ty Tái Bảo hiểm Quốc gia Việt Nam có sức khỏe tài chính tốt với tăng trưởng doanh thu và lợi nhuận. Khả năng thanh toán cao, không có nợ vay, và quản trị rủi ro hiệu quả. Triển vọng đầu tư ổn định, mặc dù phụ thuộc vào hoạt động tái bảo hiểm và đầu tư tài chính.'),
('VNR_2025_consolidated', 'VNR', 2025, 'consolidated', 'Giao dịch với các bên liên quan là giao dịch tái bảo hiểm thông thường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Doanh nghiệp không có nợ vay, áp lực nợ thấp và khả năng thanh toán cao.', 'Hàng tồn kho giá trị thấp, không có dự án xây dựng dở dang lớn, rủi ro tồn kho không đáng kể.', 3, 'Tổng Công ty có tình hình tài chính mạnh với vốn chủ sở hữu lớn, không có nợ vay, lợi nhuận tăng trưởng. Tuy nhiên, cần theo dõi các khoản đầu tư dài hạn và rủi ro từ hoạt động thí điểm bảo hiểm nông nghiệp.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNR_2023_parent', 'VNR', 2023, 'parent', 'Các giao dịch với bên liên quan diễn ra theo thông lệ kinh doanh tái bảo hiểm, không có dấu hiệu bất thường hoặc giao dịch không công bằng.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu từ hoạt động kinh doanh bảo hiểm, rủi ro thanh toán thấp.', 'Hàng tồn kho không đáng kể, nhưng chi phí xây dựng dở dang cần theo dõi tiến độ dự án để tránh ứ đọng.', 3, 'Tổng Công ty có sức khỏe tài chính tốt với lợi nhuận tăng trưởng ổn định, tỷ lệ biên khả năng thanh toán cao, và cơ cấu vốn chủ sở hữu mạnh. Tuy nhiên, cần giám sát các khoản đầu tư và dự án bất động sản để quản lý rủi ro.'),
('VNR_2024_consolidated', 'VNR', 2024, 'consolidated', 'Công ty có giao dịch lớn với nhiều bên liên quan, bao gồm cổ đông lớn và công ty con/liên kết. Các giao dịch chủ yếu là phí bảo hiểm và hoa hồng, có thể được thực hiện theo điều kiện thị trường. Tuy nhiên, mối quan hệ chặt chẽ với Tập đoàn Bảo Việt và Swiss Re có thể tạo ra xung đột lợi ích tiềm tàng, nhưng không có bằng chứng rõ ràng về giao dịch bất thường.', 'Công ty không có nợ vay tài chính đáng kể; phần lớn nợ phải trả là dự phòng nghiệp vụ tái bảo hiểm. Tuy nhiên, dự phòng này chiếm tỷ trọng lớn trong nguồn vốn, tạo áp lực về khả năng thanh toán nếu có tổn thất lớn. Biên khả năng thanh toán cao (599% tại 31/12/2024) cho thấy an toàn.', 'Tồn kho rất nhỏ (53 triệu VND) và dự án xây dựng dở dang (2,4 tỷ VND) không đáng kể, do đó rủi ro tồn kho thấp.', 4, 'Tổng Công ty có tình hình tài chính ổn định với lợi nhuận cao, biên khả năng thanh toán tốt. Tuy nhiên, hoạt động kinh doanh phụ thuộc vào thị trường bảo hiểm và đầu tư. Dự phòng nghiệp vụ lớn có thể ảnh hưởng đến lợi nhuận nếu có dao động lớn về tổn thất. Triển vọng đầu tư trung bình.'),
('VNR_2023_consolidated', 'VNR', 2023, 'consolidated', 'Tổng Công ty có giao dịch lớn với các bên liên quan, đặc biệt Tập đoàn Tái bảo hiểm Swiss Re (cổ đông 25%) với tổng phí nhượng tái 350 tỷ VNĐ và hoa hồng nhượng tái 117 tỷ VNĐ. Công ty liên kết Samsung Vina phát sinh giao dịch nhận tái bảo hiểm 126 tỷ VNĐ. Các giao dịch này theo điều kiện thị trường và hợp đồng thương mại, không có dấu hiệu bất thường về giá. Tuy nhiên, quy mô giao dịch với bên liên quan chiếm tỷ trọng đáng kể trong tổng hoạt động kinh doanh.', 'Tổng nợ phải trả là 4.285 tỷ VNĐ, trong đó dự phòng nghiệp vụ chiếm 3.117 tỷ VNĐ (72.8% tổng nợ), đây là đặc thù ngành tái bảo hiểm. Khả năng thanh toán ngắn hạn là 1.32 lần, thanh toán nhanh 0.64 lần cho thấy áp lực thanh khoản đáng kể. Tuy nhiên, biên khả năng thanh toán đạt 725% (2.497 tỷ/345 tỷ tối thiểu), vượt xa yêu cầu quy định. Công ty không có nợ vay ngân hàng dài hạn, chủ yếu dựa vào vốn chủ sở hữu và dự phòng nghiệp vụ.', 'Hàng tồn kho chỉ 3.7 tỷ VNĐ, không đáng kể. Rủi ro lớn nằm ở dự án 142 Định Công với dự phòng giảm giá 9.2 tỷ VNĐ do luật mới cấm bảo hiểm đầu tư bất động sản từ 2028. Dự án Tincom Plaza có khoản phải thu 41.2 tỷ VNĐ với dự phòng 12.7 tỷ VNĐ do bàn giao căn hộ quá hạn. Đây là rủi ro đáng chú ý.', 3, 'Tổng Công ty Tái bảo hiểm Quốc gia Việt Nam (Vinare) có kết quả kinh doanh tăng trưởng tốt năm 2023 với lợi nhuận sau thuế 423.4 tỷ VNĐ (tăng 11.9% YoY), lãi cơ bản trên cổ phiếu 2.465 đồng. Tuy nhiên, biên lợi nhuận gộp hoạt động bảo hiểm giảm từ 15.6% xuống 8.6% do chi phí bồi thường tăng mạnh. Công ty có cấu trúc vốn vững chắc với vốn chủ sở hữu 3.717 tỷ VNĐ, không có nợ vay ngân hàng. Rủi ro chính đến từ dự phòng nghiệp vụ lớn, các khoản đầu tư bất động sản dở dang có dự phòng, và phụ thuộc vào biến động tỷ giá. Triển vọng trung hạn tích cực với vị thế dẫn đầu thị trường tái bảo hiểm Việt Nam và biên khả năng thanh toán vượt xa yêu cầu.'),
('VNR_2022_consolidated', 'VNR', 2022, 'consolidated', 'Các giao dịch với bên liên quan là giao dịch kinh doanh thông thường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Doanh nghiệp không có nợ vay ngân hàng, nợ chủ yếu là phải trả thương mại, áp lực nợ thấp và có khả năng thanh toán tốt.', 'Hàng tồn kho chủ yếu là căn hộ đã nhận để trừ nợ, đã trích lập dự phòng giảm giá. Các dự án xây dựng dở dang có thể bị ứ đọng nhưng đã được đánh giá và trích lập dự phòng phù hợp.', 5, 'Tổng Công ty là doanh nghiệp tái bảo hiểm có kết quả kinh doanh ổn định, biên khả năng thanh toán cao (716%), tài sản lành mạnh và không có nợ vay. Triển vọng đầu tư tích cực với mức sinh lời hợp lý.'),
('VNR_2022_parent', 'VNR', 2022, 'parent', 'Các giao dịch với bên liên quan chủ yếu là nghiệp vụ tái bảo hiểm và thanh toán cổ tức, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Công ty không có vay nợ ngân hàng, nợ phải trả chủ yếu là dự phòng nghiệp vụ và phải trả người bán. Áp lực nợ vay thấp, khả năng thanh toán tốt.', 'Hàng tồn kho có giá trị nhỏ, chi phí xây dựng cơ bản dở dang tăng nhưng không có dấu hiệu ứ đọng. Rủi ro tồn kho thấp.', 5, 'Tổng Công ty có tình hình tài chính ổn định, lợi nhuận tăng trưởng tốt, hoạt động kinh doanh bảo hiểm chính có lãi gộp. Tuy nhiên, cần lưu ý rủi ro từ đầu tư dài hạn và biến động tỷ giá. Triển vọng tích cực trong ngắn hạn.'),
('VNR_2021_parent', 'VNR', 2021, 'parent', 'VINARE có giao dịch lớn với các bên liên quan, đặc biệt là Tập đoàn Tái bảo hiểm Swiss Re (cổ đông 25%) với tổng giao dịch phí nhượng tái và thu bồi thường lên đến hơn 400 tỷ VND, và Công ty TNHH Bảo hiểm Samsung Vina (liên kết 25%) với giao dịch nhận/nhượng tái bảo hiểm hơn 150 tỷ VND. Các giao dịch này mang tính nghiệp vụ tái bảo hiểm thông thường, tuy nhiên khối lượng giao dịch lớn với Swiss Re đặt ra câu hỏi về tính độc lập trong đàm phán điều khoản tái bảo hiểm. Dự án bất động sản Tincom Plaza với công ty con Vinare Invest có rủi ro do chủ đầu tư gặp khó khăn tài chính và đã tạm dừng thi công từ năm 2019.', 'VINARE không có nợ vay ngân hàng truyền thống mà chủ yếu là nợ phải trả thương mại (phải trả người bán ngắn hạn 483.8 tỷ VND) và dự phòng nghiệp vụ tái bảo hiểm rất lớn (3.137 tỷ VND, chiếm 45% tổng tài sản). Biên khả năng thanh toán đạt 666% (vượt xa mức tối thiểu 318 tỷ VND), thể hiện năng lực tài chính vững mạnh. Tuy nhiên, dự phòng nghiệp vụ tăng mạnh (tăng 131.8 tỷ VND so với đầu năm), đặc biệt dự phòng bồi thường nhận tái bảo hiểm tăng 220.3 tỷ VND, phản ánh áp lực bồi thường gia tăng.', 'Hàng tồn kho của VINARE không đáng kể (chỉ 23.4 triệu VND), phù hợp với đặc thù doanh nghiệp tái bảo hiểm. Rủi ro tồn kho chủ yếu đến từ chi phí xây dựng cơ bản dở dang (3.07 tỷ VND) và hai dự án bất động sản hợp tác đầu tư: dự án Tincom Plaza đã bị tạm dừng thi công và dự án 142 Định Công đang chờ phê duyệt chủ trương. Các khoản phải thu từ dự án Tincom Plaza (5.04 tỷ VND ngắn hạn) và 142 Định Công (6.17 tỷ VND dài hạn) chưa lập dự phòng nhưng có rủi ro thu hồi do tiến độ dự án chậm.', 4, 'VINARE là Tổng Công ty Tái bảo hiểm Quốc gia Việt Nam có nền tảng tài chính vững mạnh với biên khả năng thanh toán 666%, tổng tài sản 6.915 tỷ VND, vốn chủ sở hữu 3.064 tỷ VND. Lợi nhuận sau thuế năm 2021 đạt 331.7 tỷ VND (tăng 14% YoY), tỷ suất lợi nhuận sau thuế/vốn chủ sở hữu đạt 10.83%. Công ty có cơ cấu cổ đông đa dạng (SCIC 40.36%, Swiss Re 25%, Bảo Việt 9.18%). Tuy nhiên, cần lưu ý: (1) dự phòng nghiệp vụ tái bảo hiểm rất lớn (45% tổng tài sản), (2) giao dịch bên liên quan khối lượng lớn với Swiss Re, (3) một số khoản phải thu từ dự án bất động sản có rủi ro thu hồi, (4) hoạt động thí điểm bảo hiểm nông nghiệp có lỗ lũy kế chưa được quyết toán với Bộ Tài chính. Công ty duy trì chính sách thận trọng trong quản lý rủi ro và trích lập dự phòng.'),
('VNR_2020_consolidated', 'VNR', 2020, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch tái bảo hiểm nghiệp vụ với Swiss Re (cổ đông lớn 25%) và Samsung Vina (công ty liên kết 25%), phù hợp với ngành kinh doanh tái bảo hiểm. Tuy nhiên, khoản đầu tư 53,5 tỷ VNĐ vào dự án Tincom Plaza qua công ty con Vinare Invest với Công ty Thăng Long (không phải bên liên quan theo nghĩa sở hữu nhưng có mối quan hệ đầu tư phức tạp) đang gặp rủi ro do dự án bị trì hoãn, tòa HH3 ngừng thi công từ 2019. Khoản lãi 72,48 tỷ VNĐ được đánh giá là không chắc chắn thu hồi, chỉ ghi nhận là tài sản tiềm tàng.', 'Tổng nợ phải trả 3.830 tỷ VNĐ, chiếm 54,91% tổng nguồn vốn. Nợ chủ yếu là dự phòng nghiệp vụ tái bảo hiểm (3.005 tỷ VNĐ) - loại nợ đặc thù ngành bảo hiểm, phản ánh nghĩa vụ bồi thường tương lai. Biên khả năng thanh toán đạt 1.882 tỷ VNĐ, gấp 5 lần mức tối thiểu 374 tỷ VNĐ (503%), cho thấy năng lực thanh toán rất tốt. Công ty không có nợ vay ngân hàng hay trái phiếu riêng lẻ, rủi ro nợ vay thấp.', 'Hàng tồn kho chủ yếu là 10 căn hộ tại dự án Hà Nội Paragon (giá trị ghi sổ 40,96 tỷ VNĐ, đã trích lập dự phòng 4,55 tỷ VNĐ). Dự án 142 Định Công (14,04 tỷ VNĐ) vẫn đang trong giai đoạn thủ tục pháp lý, chưa khởi công xây dựng. Dự án Tincom City Plaza (7,86 tỷ VNĐ) cũng chưa hoàn thiện thủ tục chuyển nhượng do thay đổi quy hoạch. Nhìn chung, rủi ro tồn kho ở mức trung bình do đã trích lập dự phòng hợp lý cho căn hộ.', 4, 'Tổng Công ty Cổ phần Tái bảo hiểm Quốc gia Việt Nam (Vinare) có tình hình tài chính lành mạnh năm 2020. Doanh thu phí bảo hiểm thuần tăng 35% (từ 992 tỷ lên 1.340 tỷ VNĐ). Lợi nhuận sau thuế đạt 311 tỷ VNĐ, tăng 8,5% so với năm trước. Biên khả năng thanh toán 503% vượt xa yêu cầu tối thiểu. Tỷ lệ nợ/vốn 54,91% ở mức an toàn. Lưu chuyển tiền từ hoạt động kinh doanh dương 4,4 tỷ VNĐ. Điểm cần lưu ý: (1) khoản đầu tư dự án Tincom Plaza có rủi ro thu hồi, (2) dự phòng nghiệp vụ lớn (3.005 tỷ VNĐ) đặc thù ngành, (3) tiền mặt giảm mạnh từ 103 tỷ xuống 55 tỷ VNĐ do tăng đầu tư dài hạn. Triển vọng tích cực trong dài hạn nhờ vị thế là doanh nghiệp tái bảo hiểm quốc gia với đối tác chiến lược Swiss Re.'),
('VNR_2020_parent', 'VNR', 2020, 'parent', 'Các giao dịch bên liên quan chủ yếu là nghiệp vụ tái bảo hiểm với các cổ đông lớn (SCIC, Swiss Re) và công ty liên kết (Samsung Vina). Không phát hiện giao dịch bất thường như cho vay không lãi suất, mua bán chênh lệch lớn hay giao dịch với công ty sân sau của ban lãnh đạo.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu là phải trả về hợp đồng bảo hiểm và thuế. Áp lực nợ thấp, khả năng thanh toán tốt với biên khả năng thanh toán đạt 503% (vượt xa mức tối thiểu 100%). Không có tài sản thế chấp nổi bật.', 'Hàng tồn kho ở mức rất nhỏ (29 triệu VND) và chủ yếu là vật tư văn phòng. Chi phí xây dựng cơ bản dở dang 1,6 tỷ VND liên quan đến dự án đầu tư, không đáng kể. Không có rủi ro tồn kho ứ đọng.', 3, 'Tổng Công ty có kết quả kinh doanh tăng trưởng, biên lợi nhuận trước thuế đạt 18,2%, khả năng thanh toán tốt. Cấu trúc vốn lành mạnh với tỷ lệ nợ phải trả/tổng nguồn vốn 56,38%. Rủi ro chính đến từ hoạt động tái bảo hiểm và biến động tỷ giá. Công ty có vị thế thị trường vững chắc với vai trò doanh nghiệp tái bảo hiểm quốc gia, triển vọng kinh doanh ổn định.'),
('VNR_2019_consolidated', 'VNR', 2019, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan bao gồm cổ đông lớn (Swiss Re, SCIC) và công ty cùng chủ sở hữu (Bảo Minh). Các giao dịch chủ yếu là nghiệp vụ nhận/nhượng tái bảo hiểm, hoa hồng và bồi thường, đây là hoạt động kinh doanh cốt lõi của doanh nghiệp tái bảo hiểm. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất thường.', 'Công ty không có nợ vay ngân hàng, chỉ có các khoản phải trả người bán ngắn hạn và dài hạn phát sinh từ hoạt động kinh doanh tái bảo hiểm. Áp lực nợ vay thấp, khả năng thanh toán tốt với hệ số thanh toán ngắn hạn 1.51 lần.', 'Hàng tồn kho bao gồm căn hộ dự án bất động sản, đã trích lập dự phòng giảm giá. Rủi ro tồn kho ở mức trung bình do phụ thuộc vào thị trường bất động sản.', 3, 'Tổng Công ty Cổ phần Tái Bảo hiểm Quốc gia Việt Nam có tình hình tài chính ổn định với tỷ suất lợi nhuận sau thuế trên doanh thu 18.22% và ROE 9.33%. Công ty không có nợ vay ngân hàng, thanh khoản tốt. Các giao dịch bên liên quan là nghiệp vụ kinh doanh tái bảo hiểm thông thường. Công ty có cơ cấu cổ đông rõ ràng với hai cổ đông lớn là SCIC và Swiss Re. Triển vọng đầu tư tích cực trong dài hạn.'),
('VNR_2019_parent', 'VNR', 2019, 'parent', 'Tổng Công ty có giao dịch tái bảo hiểm với công ty liên kết Samsung Vina (25%) bao gồm nhận/nhượng phí tái bảo hiểm, hoa hồng và bồi thường. Không có giao dịch trọng yếu với công ty con Vinare ngoài khoản góp vốn 60 tỷ VND. Giao dịch với bên liên quan ở mức độ chấp nhận được, không có dấu hiệu bất thường rõ ràng.', 'Tổng Công ty không có vay nợ ngân hàng truyền thống. Các khoản nợ chủ yếu là phải trả liên quan đến hoạt động kinh doanh bảo hiểm (phải trả hợp đồng bảo hiểm hơn 613 tỷ VND). Nợ dài hạn chỉ có 2,8 tỷ VND (ký quỹ bảo hiểm). Cơ cấu nợ lành mạnh, không có áp lực trả nợ vay.', 'Hàng tồn kho chỉ có 36 triệu VND, không đáng kể. Dự án xây dựng dở dang 3,1 tỷ VND và bất động sản đầu tư 9,4 tỷ VND (tòa nhà 141 Lê Duẩn) có mức giá trị hợp lý. Rủi ro tồn kho và dự án ở mức thấp.', 3, 'Tổng Công ty Cổ phần Tái Bảo hiểm Quốc gia Việt Nam (VINARE) có tình hình tài chính ổn định với lợi nhuận sau thuế 274,6 tỷ VND (tăng 5% so với năm trước). Doanh thu thuần hoạt động bảo hiểm đạt 1.236,5 tỷ VND. Công ty có tỷ lệ thanh toán hiện hành 1.76 lần, ROE 9.4%. Tổng tài sản 6.772,6 tỷ VND với cơ cấu chủ yếu là đầu tư tài chính ngắn hạn (2.779 tỷ) và dài hạn (1.008 tỷ). Không có vay nợ ngân hàng, dòng tiền hoạt động kinh doanh dương 107,9 tỷ VND. Tuy nhiên, lợi nhuận gộp hoạt động bảo hiểm giảm từ 135 tỷ xuống 96,6 tỷ VND do chi bồi thường tăng mạnh. Kiểm toán viên Deloitte đưa ra ý kiến chấp nhận toàn phần.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNR_2018_parent', 'VNR', 2018, 'parent', 'Có giao dịch với công ty liên kết (Samsung Vina Insurance) liên quan đến hoạt động kinh doanh tái bảo hiểm cốt lõi. Giá trị giao dịch cụ thể không được thuyết minh chi tiết, nhưng không có dấu hiệu giao dịch bất thường cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Cấu trúc nợ chủ yếu là nợ ngắn hạn liên quan trực tiếp đến hoạt động kinh doanh bảo hiểm (dự phòng nghiệp vụ, phải trả người bán). Nợ dài hạn rất nhỏ (chủ yếu là ký quỹ bảo hiểm). Không có vay nợ ngân hàng, áp lực trả nợ thấp.', 'Doanh nghiệp là công ty tái bảo hiểm, không có hàng tồn kho vật chất. Rủi ro tồn kho là không đáng kể.', 4, 'VINARE là công ty tái bảo hiểm quốc doanh có lợi nhuận tăng trưởng ổn định, tỷ suất sinh lời trên vốn chủ sở hữu (ROE) đạt 9.3%. Cơ cấu tài sản an toàn với phần lớn đầu tư vào tiền gửi có kỳ hạn và trái phiếu. Nợ phải trả chủ yếu là các dự phòng nghiệp vụ đặc thù của ngành, không có vay nợ tài chính. Rủi ro chính đến từ biến động tỷ giá và rủi ro tín dụng từ đối tác bảo hiểm, nhưng công ty có các biện pháp quản lý rủi ro và dự phòng đầy đủ. Triển vọng kinh doanh phụ thuộc vào môi trường đầu tư và rủi ro bảo hiểm.'),
('VNR_2018_consolidated', 'VNR', 2018, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là giao dịch kinh doanh tái bảo hiểm thông thường, không có dấu hiệu bất thường về giá cả hay điều kiện phi thương mại.', 'Công ty không có nợ vay ngân hàng; nợ phải trả chủ yếu liên quan đến hợp đồng bảo hiểm và các khoản ngắn hạn, áp lực nợ thấp.', 'Tồn kho bao gồm căn hộ và dự án xây dựng dở dang, có thể chịu rủi ro thị trường bất động sản và cần theo dõi tiến độ thi công.', 3, 'Tổng Công ty hoạt động ổn định trong lĩnh vực tái bảo hiểm, lợi nhuận sau thuế tăng trưởng 16.5%, cơ cấu tài sản lành mạnh với tỷ lệ nợ phải trả giảm. Tuy nhiên, cần giám sát rủi ro đầu tư và biến động tỷ giá.'),
('VNR_2017_parent', 'VNR', 2017, 'parent', 'Công ty có giao dịch với công ty liên kết Samsung Vina (25% sở hữu) về nhận nhượng phí tái bảo hiểm và bồi thường, đây là giao dịch thương mại thông thường trong ngành bảo hiểm. Không phát hiện giao dịch bất thường với bên liên quan. Công ty con VINARE Investment được góp vốn 60 tỷ VND và có khoản hợp tác kinh doanh dự án bất động sản Tincom Plaza, Paragon Tower. Cần theo dõi hiệu quả dự án bất động sản.', 'Công ty không có nợ vay ngân hàng, cấu trúc tài chính lành mạnh với tỷ lệ nợ phải trả/tổng nguồn vốn 59.05%. Phần lớn nợ phải trả là dự phòng nghiệp vụ bảo hiểm (2,501 tỷ VND) và phải trả cho nhà tái bảo hiểm. Công ty có thanh khoản tốt với hệ số thanh toán ngắn hạn 1.40 lần và hệ số thanh toán nhanh 0.64 lần. Đầu tư chủ yếu vào tiền gửi có kỳ hạn và trái phiếu có mức lãi suất 6.7%-10.2%/năm.', 'Hàng tồn kho không đáng kể chỉ 59 triệu VND. Dự án xây dựng cơ bản dở dang chỉ 99 triệu VND, không có rủi ro ứ đọng tồn kho.', 4, 'VINARE là Tổng công ty tái bảo hiểm quốc gia có vị thế thị trường vững chắc. Tình hình tài chính lành mạnh: tỷ lệ nợ/vốn 59% an toàn, thanh khoản tốt, biên lợi nhuận gộp 12.39%. Lợi nhuận trước thuế 285.29 tỷ VND, tăng 5.4% so với năm trước. Công ty được Deloitte kiểm toán với ý kiến chấp nhận toàn phần, không có vấn đề going concern. Cổ đông lớn là SCIC (40.36%) và Swiss Re (25%) tạo nền tảng quản trị tốt. Công ty trả cổ tức cao (22% vốn góp) cho thấy khả năng sinh lời ổn định.'),
('VNR_2016_consolidated', 'VNR', 2016, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là nghiệp vụ nhận và nhượng tái bảo hiểm, hoa hồng, bồi thường và cổ tức. Đây là các giao dịch thương mại bình thường trong ngành bảo hiểm, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn đáng ngờ.', 'Công ty không có nợ vay ngân hàng rõ ràng. Nợ phải trả chủ yếu bao gồm dự phòng nghiệp vụ (dự phòng bồi thường, dự phòng phí) và phải trả người bán. Áp lực nợ vay thấp, khả năng thanh toán đảm bảo. Không có tài sản thế chấp nổi bật được đề cập.', 'Hàng tồn kho rất nhỏ (53.899.538 VND), không đáng kể. Có tài sản dở dang là chi phí xây dựng cơ bản dở dang và đặt cọc mua bất động sản, nhưng không có thông tin về rủi ro ứ đọng hay chậm tiến độ.', 3, 'Tổng Công ty Cổ phần Tái Bảo hiểm Quốc gia Việt Nam là doanh nghiệp tái bảo hiểm nhà nước, hoạt động kinh doanh ổn định. Lợi nhuận sau thuế năm 2016 đạt 239.984.779.653 VND, giảm nhẹ so với năm trước. Cơ cấu tài sản chủ yếu là đầu tư tài chính ngắn hạn và dài hạn, thanh khoản tốt. Nợ phải trả chủ yếu là dự phòng nghiệp vụ, không có nợ vay ngân hàng áp lực. Điểm rủi ro quản trị thấp. Triển vọng trung bình do chịu ảnh hưởng từ thị trường bảo hiểm và đầu tư.'),
('VNR_2017_consolidated', 'VNR', 2017, 'consolidated', 'Công ty có giao dịch lớn với các bên liên quan bao gồm Swiss Re (cổ đông 25%), Bảo Minh (cùng chủ sở hữu SCIC) và Samsung Vina (công ty liên kết 25%). Các giao dịch chủ yếu là nghiệp vụ nhận/nhượng tái bảo hiểm, hoa hồng và bồi thường - phản ánh bản chất kinh doanh tái bảo hiểm. Đặc biệt, phí nhận tái bảo hiểm từ Samsung Vina lên tới 133 tỷ VND và bồi thường nhận 116 tỷ VND cho thấy mức độ phụ thuộc đáng kể. Cổ tức trả cho Swiss Re (39.3 tỷ) và SCIC (63.5 tỷ) là hoạt động phân phối lợi nhuận thông thường. Nhìn chung, giao dịch với bên liên quan mang tính nghiệp vụ ngành, chưa phát hiện dấu hiệu bất thường nhưng cần theo dõi mức độ tập trung rủi ro.', 'Công ty không có nợ vay ngân hàng, nợ phải trả chủ yếu phát sinh từ hoạt động kinh doanh tái bảo hiểm (phải trả người bán, dự phòng nghiệp vụ). Dự phòng nghiệp vụ chiếm tỷ trọng lớn (2,500 tỷ VND) phản ánh tính thận trọng trong trích lập. Hệ số thanh toán nhanh chỉ 0.64 lần cho thấy khả năng thanh toán ngắn hạn hạn chế. Tỷ lệ nợ phải trả/tổng tài sản là 57.84% ở mức trung bình cao đối với doanh nghiệp bảo hiểm. Tuy nhiên, công ty có tài sản tài chính lớn (đầu tư ngắn hạn 2,218 tỷ) và dòng tiền hoạt động kinh doanh dương, nên rủi ro thanh toán ở mức kiểm soát được.', 'Hàng tồn kho chỉ 59 triệu VND - không đáng kể. Có 13.5 tỷ VND chi phí xây dựng cơ bản dở dang và 66.2 tỷ VND đặt cọc mua bất động sản (Dự án Paragon Tower và Tincom Plaza). Các khoản đặt cọc này là tài sản dài hạn có tính thanh khoản thấp. Công ty đánh giá không có suy giảm đáng kể về giá trị khoản đặt cọc. Rủi ro tồn kho ở mức thấp do tỷ trọng nhỏ trong tổng tài sản.', 5, 'Tổng Công ty Tái Bảo hiểm Quốc gia Việt Nam (VINARE) thể hiện sức khỏe tài chính ổn định với lợi nhuận sau thuế đạt 259.2 tỷ VND, tăng 8% so với năm trước. Biên lợi nhuận gộp hoạt động kinh doanh bảo hiểm 12.4%, tỷ suất lợi nhuận sau thuế/vốn chủ sở hữu 9.64%. Công ty thanh toán cổ tức 22% cho cổ đông. Điểm mạnh: không có nợ vay ngân hàng, cấu trúc sở hữu rõ ràng với SCIC (40.36%) và Swiss Re (25%), hệ thống quản trị rủi ro chuyên nghiệp. Điểm cần lưu ý: hệ số thanh toán nhanh thấp (0.64), tỷ lệ nợ phải trả/tổng tài sản 57.84% ở mức trung bình cao, lỗ lũy kế từ hoạt động thí điểm bảo hiểm nông nghiệp (42 tỷ VND). Hoạt động bảo hiểm tàu cá mang lại chênh lệch dương 3.4 tỷ VND. Công ty đầu tư chiến lược vào nhiều công ty bảo hiểm và ngân hàng (Tiên Phong Bank 275 tỷ, Bảo hiểm Petrolimex 59 tỷ, v.v.). Dòng tiền hoạt động kinh doanh dương 6.5 tỷ VND. Triển vọng phát triển trung hạn ổn định, phù hợp với ngành tái bảo hiểm.'),
('VNR_2015_parent', 'VNR', 2015, 'parent', 'Giao dịch với các bên liên quan bao gồm nhận và nhượng phí tái bảo hiểm, hoa hồng và bồi thường với Công ty TNHH Bảo hiểm Samsung Vina, nhưng không có thông tin về giao dịch bất thường hoặc giá trị lớn.', 'Nợ phải trả chủ yếu là dự phòng nghiệp vụ bảo hiểm và phải trả người bán ngắn hạn. Công ty có tỷ lệ nợ phải trả trên tổng nguồn vốn là 59,80% (31/12/2015), nhưng khả năng thanh toán hiện hành là 1,67 lần, cho thấy khả năng thanh toán đầy đủ.', 'Hàng tồn kho và tài sản dở dang chiếm tỷ trọng rất nhỏ trong tổng tài sản, không gây rủi ro đáng kể.', 2, 'Công ty tái bảo hiểm có lợi nhuận sau thuế giảm từ 364,814,718,240 VND năm 2014 xuống 225,033,568,563 VND năm 2015. Tài sản và vốn chủ sở hữu ổn định. Công ty quản lý rủi ro tỷ giá và tín dụng hiệu quả. Triển vọng trung lập do ảnh hưởng của môi trường kinh doanh bảo hiểm.'),
('VNR_2016_parent', 'VNR', 2016, 'parent', 'Tổng Công ty có giao dịch tái bảo hiểm với Công ty TNHH Bảo hiểm Samsung Vina (công ty liên kết 25%). Không có giao dịch trọng yếu với Công ty Cổ phần Đầu tư Vinare (công ty con). Tuy nhiên, Tổng Công ty đầu tư góp vốn vào nhiều công ty bảo hiểm khác (Petrolimex Insurance 8.76%, PTI 4.42%, Toàn Cầu 4.4%, Phú Hưng 2.26%, ABIC 8.42%, Hùng Vương 10%) tạo mạng lưới đầu tư chéo trong ngành bảo hiểm. Có ủy thác đầu tư qua 3 quỹ/chứng khoán (VCBF, Bảo Việt Fund, SSI) với giá trị 207 tỷ VND, trong đó có dự phòng giảm giá 1.89 tỷ VND. Rủi ro xung đột lợi ích ở mức vừa phải do mối quan hệ đầu tư phức tạp trong cùng ngành.', 'Tổng Công ty không có nợ vay ngân hàng truyền thống. Nợ phải trả chủ yếu là dự phòng nghiệp vụ tái bảo hiểm (phải trả về hợp đồng bảo hiểm 608 tỷ, dự phòng phí 789 tỷ, dự phòng bồi thường 1,583 tỷ, dự phòng dao động lớn 192 tỷ) - đặc thù ngành kinh doanh tái bảo hiểm. Có khoản phải trả liên quan hợp đồng hoán đổi ngoại tệ 248 tỷ VND phục vụ phòng ngừa rủi ro tỷ giá. Khả năng thanh toán nợ ngắn hạn tốt (hệ số thanh toán ngắn hạn 1.38 lần, hệ số thanh toán nhanh 0.59 lần). Tỷ lệ nợ/tổng nguồn vốn 57.57% chủ yếu do dự phòng nghiệp vụ chiếm tỷ trọng lớn.', 'Hàng tồn kho không đáng kể (chỉ 54 triệu VND trên tổng tài sản 6,239 tỷ VND), do đặc thù ngành tái bảo hiểm không có hàng hóa vật chất. Chi phí xây dựng cơ bản dở dang chỉ 99 triệu VND, không có rủi ro ứ đọng dự án. Không có rủi ro tồn kho.', 4, 'Tổng Công ty Tái Bảo hiểm Quốc gia Việt Nam có vị thế tài chính vững mạnh với tổng tài sản 6,239 tỷ VND, vốn chủ sở hữu 2,647 tỷ VND. Tỷ suất lợi nhuận trước thuế/doanh thu đạt 22.49%, ROE 8.44%, ROA 4.34%. Lợi nhuận sau thuế ổn định quanh 223-225 tỷ VND. Công ty không có nợ vay ngân hàng, thanh khoản tốt với tiền gửi có kỳ hạn lên đến 2,602 tỷ VND (lãi suất 6-10.2%/năm). Tuy nhiên, doanh thu phí bảo hiểm thuần giảm nhẹ từ 587 tỷ xuống 569 tỷ, chi phí quản lý doanh nghiệp tăng mạnh 36% (từ 65 tỷ lên 89 tỷ). Đầu tư tài chính dài hạn và ngắn hạn chiếm tỷ trọng lớn (3,269 tỷ VND - 52% tổng tài sản). Công ty có mạng lưới đầu tư rộng vào nhiều doanh nghiệp bảo hiểm khác trong ngành. Kết quả hoạt động thí điểm bảo hiểm nông nghiệp có lỗ 47 triệu VND. Triển vọng ổn định nhờ vị thế là doanh nghiệp tái bảo hiểm quốc gia với SCIC nắm 40.36% vốn.'),
('VNP_2025_consolidated', 'VNP', 2025, 'consolidated', 'Công ty có các giao dịch lớn với các công ty liên doanh, liên kết như Công ty TNHH Liên doanh Việt Thái Plastchem, Công ty TNHH Nhựa và Hóa chất TPC Vina và đặc biệt khoản phải thu khách hàng lớn từ Công ty Cổ phần Nhựa Vân Đồn (47,36 tỷ VND) đã trích lập dự phòng 100% do đối tác gặp khó khăn tài chính và đang trong quá trình phá sản. Điều này cho thấy rủi ro tín dụng cao và tiềm ẩn giao dịch không hiệu quả với các bên liên quan.', 'Áp lực nợ vay đã giảm đáng kể (từ 46,67 tỷ xuống 7,51 tỷ VND) nhờ thanh toán hết nợ vay Ngân hàng Phát triển Việt Nam. Tuy nhiên, khoản vay còn lại tại Ngân hàng TMCP Ngoại thương Việt Nam (7,11 tỷ VND) đã quá hạn thanh toán và bị chuyển hồ sơ sang cơ quan thi hành án, tạo rủi ro pháp lý và tài chính nghiêm trọng. Nợ không lãi suất từ cá nhân (0,4 tỷ VND) cũng tồn tại.', 'Hàng tồn kho giảm mạnh (từ 32,36 tỷ xuống 14,09 tỷ VND) do Công ty con - Công ty Cổ phần Nhựa Việt Phước đã tạm dừng hoạt động sản xuất từ tháng 02/2024 để thanh lý hàng hóa và tài sản. Dự phòng giảm giá hàng tồn kho vẫn ở mức cao (8,65 tỷ VND), tập trung vào nguyên liệu và thành phẩm. Rủi ro tồn kho giảm nhưng vẫn cần theo dõi tiến độ thanh lý.', 6, 'Sức khỏe tài chính của Công ty có sự cải thiện so với năm trước do giảm mạnh nợ vay và quản lý chi phí tốt hơn. Tuy nhiên, doanh thu sụt giảm mạnh (từ 78,63 tỷ xuống 42,13 tỷ VND) và lợi nhuận gộp âm (-1,24 tỷ VND). Lợi nhuận sau thuế dương (17,83 tỷ VND) chủ yếu nhờ vào lợi nhuận từ công ty liên kết (31,27 tỷ VND) và doanh thu hoạt động tài chính (4,97 tỷ VND). Công ty đối mặt với rủi ro lớn từ khoản phải thu khó đòi với bên liên quan, nợ vay quá hạn, và hoạt động sản xuất kinh doanh chính suy giảm. Triển vọng đầu tư cần thận trọng.'),
('VNP_2025_parent', 'VNP', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm cho vay và phải thu, nhưng không có dấu hiệu bất thường rõ ràng. Tuy nhiên, một số công ty con đã ngừng hoạt động, đòi hỏi phải quản lý cẩn thận.', 'Công ty không có nợ vay, rủi ro nợ thấp.', 'Hàng tồn kho có dự phòng giảm giá, nhưng giá trị không quá lớn, rủi ro ở mức trung bình.', 6, 'Công ty có sức khỏe tài chính ổn định với lợi nhuận tăng trưởng, không có nợ, nhưng tồn tại rủi ro từ các khoản đầu tư vào công ty con và liên kết. Triển vọng phụ thuộc vào khả năng thu hồi các khoản phải thu và quản lý hoạt động kinh doanh.'),
('VNP_2024_parent', 'VNP', 2024, 'parent', 'Có nhiều giao dịch lớn với các công ty con và liên kết, đặc biệt là khoản phải thu ngắn hạn từ Công ty Cổ phần Nhựa Vân Đồn (47.3 tỷ VNĐ) và Công ty Cổ phần Nhựa Việt Phước (4.5 tỷ VNĐ). Các khoản phải thu này đã được trích lập dự phòng 100% cho thấy rủi ro thu hồi cao. Công ty con Nhựa Việt Phước có lỗ lũy kế vượt vốn chủ sở hữu.', 'Nợ vay ngắn hạn giảm mạnh từ 74.4 tỷ xuống 38.3 tỷ VNĐ. Khoản vay từ Ngân hàng Phát triển Việt Nam đã quá hạn thanh toán, lãi suất phạt 4.8%/năm. Tài sản thế chấp là máy móc, thiết bị có nguyên giá lớn (102.9 tỷ VNĐ) nhưng giá trị còn lại 0 VND do đã khấu hao hết.', 'Hàng tồn kho giảm mạnh từ 42.2 tỷ xuống 26.5 tỷ VNĐ, dự phòng giảm giá giảm từ 12.9 tỷ xuống 3.8 tỷ VNĐ. Công ty đã hoàn nhập dự phòng lớn 9.5 tỷ VNĐ trong năm, cho thấy xử lý hàng tồn kho chậm chuyển tốt. Hàng hóa tồn kho chủ yếu là hàng hóa thương mại.', 6, 'Công ty CP Nhựa Việt Nam ghi nhận sự phục hồi mạnh về lợi nhuận trong năm 2024 (lãi 14.7 tỷ VNĐ hợp nhất, so với lỗ 10.6 tỷ năm 2023) nhờ hoàn nhập dự phòng tồn kho và giảm chi phí. Tuy nhiên, công ty vẫn đối mặt với rủi ro lớn từ các khoản phải thu khó đòi từ bên liên quan (đã trích lập 100% dự phòng) và nợ vay quá hạn. Cơ cấu tài sản chủ yếu là đầu tư tài chính dài hạn vào các công ty con/liên kết có hiệu quả hoạt động không đồng đều.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNP_2024_consolidated', 'VNP', 2024, 'consolidated', 'Công ty có giao dịch với các bên liên quan bao gồm công ty liên doanh và cổ đông lớn, với các giao dịch chia lợi nhuận và hoa hồng. Khoản đầu tư vào Công ty Cổ phần Nhựa Vân Đồn đang trong quá trình phá sản, và các khoản phải thu từ bên liên quan lớn, gây rủi ro thu hồi nợ và giá trị đầu tư.', 'Nợ vay ngắn hạn đều đã quá hạn thanh toán với lãi suất cao và tài sản thế chấp. Công ty đang đàm phán gia hạn nợ nhưng áp lực thanh toán lớn. Nợ thuần trên vốn chủ sở hữu là 12.17%, giảm so với năm trước, nhưng rủi ro vẫn cao do nợ quá hạn.', 'Hàng tồn kho đã giảm mạnh nhờ bán hàng và hoàn nhập dự phòng. Dự phòng giảm giá được hoàn nhập một phần, cho thấy hàng tồn lưu thông. Tuy nhiên, vẫn có rủi ro từ hàng tồn kho chậm luân chuyển và giá trị tồn kho cao.', 7, 'Công ty đã chuyển sang lãi trong năm 2024 sau lỗ năm 2023 nhờ hoàn nhập dự phòng tồn kho và giảm chi phí. Tuy nhiên, nợ vay quá hạn và dòng tiền yếu là rủi ro lớn. Triển vọng đầu tư phụ thuộc vào khả năng giải quyết nợ và tái cơ cấu hoạt động.'),
('VNP_2023_parent', 'VNP', 2023, 'parent', 'Doanh nghiệp có các giao dịch với bên liên quan bao gồm phải thu và cho vay, trong đó nhiều khoản phải thu đã trích lập dự phòng 100% cho thấy rủi ro thu hồi cao. Các giao dịch này chủ yếu với công ty con và công ty liên kết, có thể ảnh hưởng đến kết quả tài chính nếu không được quản lý chặt chẽ.', 'Khoản vay ngắn hạn từ Ngân hàng Phát triển Việt Nam đã quá hạn thanh toán, với lãi phạt chậm trả cao. Tuy nhiên, khoản vay được đảm bảo bằng tài sản cố định, giảm thiểu rủi ro. Tỷ lệ nợ thuần trên vốn chủ sở hữu ở mức 19% cho thấy áp lực nợ ở mức kiểm soát được.', 'Hàng tồn kho đã trích lập dự phòng giảm giá tăng cao (từ 6.67 tỷ VND lên 12.93 tỷ VND) do giá trị thuần có thể thực hiện thấp hơn giá gốc, phản ánh rủi ro ứ đọng và giảm giá hàng hóa trong bối cảnh thị trường yếu.', 5, 'Công ty Cổ phần Nhựa Việt Nam ghi nhận kết quả kinh doanh lỗ trong năm 2023 do doanh thu giảm mạnh vì nhu cầu thị trường yếu và giá nguyên liệu giảm sâu. Tuy nhiên, công ty có nguồn thu nhập tài chính từ lãi tiền gửi và cổ tức từ các công ty liên doanh. Cơ cấu vốn tương đối ổn định với tỷ lệ nợ thấp, nhưng tồn kho và phải thu có rủi ro. Triển vọng phụ thuộc vào sự phục hồi của thị trường nhựa và hiệu quả quản lý nợ, tồn kho.'),
('VNP_2023_consolidated', 'VNP', 2023, 'consolidated', 'Các giao dịch với các bên liên quan chủ yếu là phân chia lợi nhuận và doanh thu hoa hồng từ các công ty liên doanh, liên kết, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Áp lực nợ vay ngắn hạn ở mức trung bình, với tài sản thế chấp bao gồm hàng tồn kho và tài sản cố định. Công ty có dòng tiền từ hoạt động đầu tư và kinh doanh để đảm bảo thanh toán, nhưng rủi ro lãi suất và tỷ giá vẫn tồn tại.', 'Rủi ro tồn kho cao với dự phòng giảm giá hàng tồn kho lớn, đặc biệt cho nguyên liệu, vật liệu và hàng hóa, do giá giảm sâu và nhu cầu thị trường yếu. Hàng tồn kho được dùng để thế chấp cho khoản vay.', 5, 'Công ty trải qua năm 2023 thua lỗ do nhu cầu thị trường yếu, giá nguyên liệu giảm sâu và chi phí dự phòng hàng tồn kho tăng cao. Cơ cấu nợ ngắn hạn với tài sản thế chấp, nhưng thanh khoản vẫn được đảm bảo. Triển vọng phụ thuộc vào sự phục hồi của thị trường nhựa và hiệu quả hoạt động của các công ty liên doanh, liên kết.'),
('VNP_2022_consolidated', 'VNP', 2022, 'consolidated', 'Rủi ro giao dịch bên liên quan ở mức CAO. Công ty có khoản phải thu lớn từ các công ty con và liên kết: phải thu từ Công ty CP Nhựa Vân Đồn (liên kết) là 47,3 tỷ VND đã trích lập dự phòng 100% do công ty này đang trong thủ tục phá sản. Phải thu từ các công ty con khác (Việt Phước, Trường An, Số Một) cũng có tỷ lệ dự phòng cao. Khoản góp vốn dự án 21 tỷ vào Nhựa Thăng Long chưa thu hồi được. Tuy nhiên, khoản đầu tư vào TPC Vina và Việt Thái Plastchem mang lại lợi nhuận chia tốt (tổng 57 tỷ VND trong năm 2022). Công ty có nhiều giao dịch nội bộ với công ty con bao gồm cho vay, cho thuê, mua bán hàng hóa.', 'Áp lực nợ vay ở mức TRUNG BÌNH-CAO. Nợ vay ngắn hạn 91,36 tỷ VND tập trung tại Ngân hàng Phát triển Việt Nam và đã QUÁ HẠN thanh toán. Khoản vay ODA này đã được kiến nghị khoanh nợ nhưng Bộ Tài chính chưa xử lý, cuộc họp ngày 31/3/2022 cũng chưa có kết luận. Tuy nhiên, tỷ lệ nợ thuần/vốn chủ sở hữu đã cải thiện từ 0,50 xuống 0,33. Công ty có nợ gốc quá hạn bằng CNY là 26.966.315,62 CNY. Tài sản thế chấp bao gồm tiền gửi có kỳ hạn tại HDBank và tài sản cố định đã khấu hao hết.', 'Rủi ro tồn kho ở mức TRUNG BÌNH. Dự phòng giảm giá hàng tồn kho tăng đột biến từ 54 triệu VND (2021) lên 6,67 tỷ VND (2022) do giá bán giảm sau niên độ. Hàng tồn kho tăng mạnh từ 13,3 tỷ lên 68,2 tỷ VND, trong đó có 3,7 tỷ hàng đang vận chuyển. Dự án bất động sản 21 tỷ chưa thu hồi được, đang trong quá trình chuyển nhượng.', 7, 'Công ty CP Nhựa Việt Nam đang trong giai đoạn khó khăn tài chính đáng kể: doanh thu giảm 43,6% (từ 317 tỷ xuống 179 tỷ VND), lợi nhuận gộp biên rất thấp chỉ 1,77%, và hoạt động kinh doanh chính tạo ra dòng tiền âm 104 tỷ VND. Nguồn thu nhập chính đến từ cổ tức/lợi nhuận được chia từ các công ty liên doanh (57 tỷ VND) chứ không phải từ hoạt động sản xuất kinh doanh cốt lõi. Công ty có nợ ODA quá hạn chưa được xử lý, nhiều khoản phải thu từ bên liên quan đã trích lập dự phòng 100%, và đầu tư vào các công ty con phần lớn đang lỗ hoặc ngừng hoạt động. Công ty có lỗ tính thuế lũy kế 53 tỷ VND. Điểm tích cực là tỷ lệ đòn bẩy đã cải thiện và Công ty vẫn có lợi nhuận sau thuế 51,4 tỷ VND chủ yếu nhờ hoạt động đầu tư tài chính. Tuy nhiên, triển vọng phụ thuộc lớn vào khả năng xử lý nợ ODA, thu hồi công nợ từ bên liên quan, và cải thiện biên lợi nhuận gộp trong hoạt động kinh doanh chính.'),
('VNP_2021_consolidated', 'VNP', 2021, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là chia lợi nhuận và cho thuê tài sản, không có dấu hiệu bất thường về lãi suất hay giá cả. Tuy nhiên, Công ty Cổ phần Nhựa Vân Đồn đã mở thủ tục phá sản, có thể ảnh hưởng đến khả năng thu hồi công nợ.', 'Áp lực nợ vay không cao do công ty có khả năng thanh toán từ dòng tiền hoạt động. Nợ dài hạn đã quá hạn nhưng được khoanh nợ và xin phép xử lý. Tài sản thế chấp đầy đủ.', 'Tồn kho có dự phòng giảm giá nhỏ và một phần hàng hóa chậm luân chuyển, nhưng không đáng kể. Không có dự án xây dựng dở dang.', 6, 'Công ty có kết quả kinh doanh tăng trưởng tốt nhờ lợi nhuận từ công ty liên doanh. Tình hình tài chính ổn định, nợ vay được kiểm soát. Tuy nhiên, cần lưu ý rủi ro từ công ty liên doanh phá sản và áp lực thanh toán nợ dài hạn quá hạn.'),
('VNP_2019_parent', 'VNP', 2019, 'parent', 'Có giao dịch phức tạp với các công ty con và liên kết, bao gồm cho vay, bán hàng và nhận cổ tức. Một số khoản phải thu đã được trích lập dự phòng đầy đủ, đặc biệt là Công ty CP Nhựa Vân Đồn, cho thấy rủi ro tín dụng cao với bên liên quan.', 'Nợ vay chủ yếu từ ngân hàng với lãi suất cố định, có tài sản thế chấp. Tuy nhiên, nợ ngắn hạn cao, áp lực trả nợ lớn. Có khoản vay ODA với lãi suất thấp nhưng đang chờ xử lý khoanh nợ từ Bộ Tài chính.', 'Hàng tồn kho không có ứ đọng hay mất phẩm chất, dự phòng giảm giá ở mức thấp, rủi ro thấp.', 6, 'Công ty có sức khỏe tài chính trung bình, với lợi nhuận giảm sút so với năm trước do cạnh tranh gay gắt. Nợ vay cao và giao dịch bên liên quan phức tạp tạo áp lực tài chính. Triển vọng đầu tư cần thận trọng.'),
('VNP_2020_consolidated', 'VNP', 2020, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan, bao gồm cho vay và cho thuê tài sản cho các công ty con, có thể tiềm ẩn rủi ro về tính công bằng và khả năng thu hồi nợ. Nhiều khoản phải thu đã trích lập dự phòng lớn.', 'Nợ ngắn hạn vượt quá tài sản ngắn hạn, áp lực trả nợ lớn. Công ty đang chờ gia hạn nợ từ ngân hàng phát triển và nợ gốc quá hạn lớn.', 'Hàng tồn kho giảm so với đầu năm, không có dự phòng giảm giá, nhưng không có rủi ro lớn về tồn kho ứ đọng.', 7, 'Sức khỏe tài chính của Công ty đang gặp thách thức do nợ ngắn hạn cao, lỗ lũy kế và khả năng thanh toán hạn chế. Công ty đang nỗ lực cắt giảm chi phí và xin gia hạn nợ. Triển vọng đầu tư thận trọng.'),
('VNP_2019_consolidated', 'VNP', 2019, 'consolidated', 'Công ty có các giao dịch với bên liên quan bao gồm cho thuê tài sản và nhận cổ tức từ công ty liên kết. Các giao dịch này được thực hiện theo giá thị trường nhưng cần theo dõi sát để đảm bảo không có xung đột lợi ích.', 'Công ty có áp lực nợ vay cao với tổng nợ vay hơn 151 tỷ VNĐ, bao gồm khoản vay ODA dài hạn lãi suất thấp nhưng cần được Bộ Tài chính phê duyệt khoanh nợ. Quản trị đánh giá rủi ro thanh khoản ở mức cao, tuy nhiên công ty có tài sản thế chấp và dòng tiền hoạt động dương.', 'Hàng tồn kho chủ yếu là nguyên liệu và thành phẩm, có trích lập dự phòng giảm giá nhưng không có hàng tồn kho ứ động hay mất phẩm chất. Rủi ro tồn kho ở mức thấp.', 5, 'Công ty CP Nhựa Việt Nam đang gặp khó khăn trong năm 2019 với lợi nhuận sau thuế lỗ 1,8 tỷ VNĐ so với lãi 39,6 tỷ VNĐ năm 2018, do doanh thu giảm và chi phí tài chính tăng. Công ty có gánh nặng nợ vay lớn và ý kiến kiểm toán ngoại trừ do khoản đầu tư vào công ty liên kết chưa có báo cáo kiểm toán. Tuy nhiên, công ty có tài sản thế chấp và sự hỗ trợ từ nhà nước, triển vọng trung hạn cần thận trọng.'),
('VNP_2018_consolidated', 'VNP', 2018, 'consolidated', 'Doanh nghiệp có giao dịch với các công ty liên kết, bao gồm nhận cổ tức và cho thuê tài sản. Các khoản phải thu từ bên liên quan có dự phòng lớn, cho thấy rủi ro tín dụng.', 'Áp lực nợ vay cao với tổng nợ vay hơn 152 tỷ đồng. Công ty đã sử dụng tài sản thế chấp cho các khoản vay. Dòng tiền từ hoạt động kinh doanh âm, đặt ra rủi ro thanh khoản.', 'Hàng tồn kho chủ yếu là nguyên liệu và thành phẩm, đã trích lập dự phòng giảm giá. Không có dự án bất động sản lớn.', 6, 'Doanh nghiệp có lợi nhuận sau thuế giảm so với năm trước, nhưng vẫn có lợi nhuận. Nợ vay cao và dòng tiền hoạt động kinh doanh âm cho thấy áp lực tài chính. Cần theo dõi khả năng thanh toán và quản lý nợ.'),
('VNP_2018_parent', 'VNP', 2018, 'parent', 'Các giao dịch với bên liên quan chủ yếu cho vay và cho thuê tài sản, không có dấu hiệu bất thường về giá cả hay điều kiện đặc biệt.', 'Áp lực nợ vay ở mức trung bình, với nợ dài hạn主要集中于 phát triển Việt Nam, lãi suất cố định 3.2%/năm. Có rủi ro về lãi quá hạn nếu Bộ Tài chính không chấp thuận khoanh nợ theo kiến nghị.', 'Hàng tồn kho có dự phòng giảm giá nhưng không có hàng ứ đọng hay kém chất lượng, rủi ro tồn kho thấp.', 5, 'Doanh nghiệp có nợ vay tương đối cao so với vốn chủ sở hữu, lợi nhuận giảm mạnh do không còn thu nhập từ chuyển nhượng bất động sản. Tuy nhiên, công ty vẫn duy trì hoạt động liên tục và có dòng tiền từ hoạt động đầu tư dương. Đánh giá rủi ro ở mức trung bình.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNP_2017_consolidated', 'VNP', 2017, 'consolidated', 'Công ty có phát sinh giao dịch bán hàng lớn với các bên liên quan (Công ty CP Nhựa Vân Đồn, Công ty CP Nhựa Thăng Long). Các khoản phải thu từ bên liên quan chiếm tỷ trọng đáng kể (gần 50% tổng phải thu khách hàng ngắn hạn). Rủi ro tập trung vào khả năng thanh toán của các đối tác này, đặc biệt trong bối cảnh một số khách hàng đã bị khởi kiện do không thanh toán đúng hạn.', 'Tổng nợ vay giảm từ 180,7 tỷ đồng xuống 169,5 tỷ đồng. Nợ thuần trên vốn chủ sở hữu giảm mạnh từ 248,1% xuống 89,8%. Các khoản vay chủ yếu từ ngân hàng nhà nước (BIDV, Vietcombank, VDB) có tài sản đảm bảo là máy móc và quyền sử dụng đất. Rủi ro chính là khoản vay ODA đang chờ Bộ Tài chính chấp thuận khoanh nợ, nếu không được chấp thuận có thể phát sinh lãi phạt khoảng 5 tỷ đồng.', 'Giá trị hàng tồn kho giảm nhẹ từ 55,5 tỷ xuống 50,6 tỷ đồng. Dự phòng giảm giá hàng tồn kho ở mức thấp (106 triệu đồng). Hàng tồn kho chủ yếu là nguyên liệu và thành phẩm, không có dấu hiệu ứ đọng nghiêm trọng. Công ty đã hoàn nhập một phần dự phòng giảm giá hàng tồn kho trong năm.', 6, 'Lợi nhuận sau thuế hợp nhất năm 2017 tăng mạnh (60,2 tỷ đồng so với 28,9 tỷ đồng năm 2016) chủ yếu nhờ thu nhập lớn từ chuyển nhượng tòa nhà (85,1 tỷ đồng) và cổ tức từ công ty liên doanh/liên kết (53 tỷ đồng). Tuy nhiên, hoạt động kinh doanh chính suy giảm (doanh thu thuần giảm, lợi nhuận gộp tăng nhẹ nhưng chi phí tài chính tăng cao do lỗ chênh lệch tỷ giá). Công ty đang trong quá trình thoái vốn nhà nước và chuyển đổi sở hữu. Điểm kiểm toán ngoại trừ do không thu thập được đầy đủ biên bản đối chiếu nợ phải thu (50,8 tỷ đồng cuối năm) là rủi ro về chất lượng công nợ.'),
('VNP_2017_parent', 'VNP', 2017, 'parent', 'Doanh nghiệp có lượng giao dịch lớn với các bên liên quan: phải thu từ Công ty CP Nhựa Vân Đồn (liên kết) lên tới hơn 43,8 tỷ đồng; phải trả cho Công ty CP Nhựa Youl Chon Vina (liên kết) gần 37 tỷ đồng là nợ quá hạn. Ngoài ra có khoản góp vốn hợp tác kinh doanh 21 tỷ đồng với Công ty CP Nhựa Thăng Long (liên quan qua đồng Chủ tịch HĐQT). Các khoản đầu tư vào công ty con có dự phòng tổn thất tổng cộng 47,2 tỷ đồng, trong đó Công ty TNHH MTV TM&DV Nhựa Trường An và Nhựa Số Một có dự phòng gần bằng toàn bộ vốn góp, cho thấy hiệu quả đầu tư kém. Tuy nhiên, không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn bất hợp lý.', 'Tổng nợ vay 147,2 tỷ đồng, tỷ lệ nợ thuần/vốn chủ sở hữu đạt 99%. Nợ ngắn hạn vượt tài sản ngắn hạn 55,8 tỷ đồng. Công ty có lỗ lũy kế 100 tỷ đồng. Khoản vay ODA từ Ngân hàng Phát triển Việt Nam vẫn chưa được Bộ Tài chính chấp thuận khoanh nợ, nếu không được chấp thuận có thể chịu lãi quá hạn ước tính 4,9 tỷ đồng. Tài sản thế chấp bao gồm tài sản cố định tại Bình Dương, tiền gửi ngân hàng 37,5 tỷ đồng và quyền đòi nợ khách hàng. Áp lực trả nợ trong vòng 1 năm là rất lớn (hơn 102,7 tỷ đồng nợ ngắn hạn + 88,9 tỷ nợ dài hạn đến hạn trả).', 'Tồn kho giảm mạnh từ 29 tỷ xuống 15,6 tỷ đồng. Dự phòng giảm giá tồn kho giảm từ 143 triệu xuống 106 triệu, Công ty đã hoàn nhập 37 triệu đồng dự phòng. Hàng hóa chiếm phần lớn tồn kho (5 tỷ đồng) và có dự phòng. Các chi phí xây dựng cơ bản dở dang nhỏ (286 triệu), chủ yếu là nhà xưởng Mỹ Phước mới phát sinh và chi phí chuyển đổi sản xuất tấm chống thấm. Rủi ro tồn kho ở mức thấp đến trung bình.', 7, 'Công ty CP Nhựa Việt Nam đang trong tình trạng tài chính khó khăn với lỗ lũy kế 100 tỷ đồng, nợ ngắn hạn vượt tài sản ngắn hạn, và nhận ý kiến kiểm toán ngoại trừ do chưa xác nhận đầy đủ công nợ phải thu. Tuy nhiên, năm 2017 đã có lợi nhuận 71,4 tỷ đồng (chủ yếu từ chuyển nhượng tòa nhà 39A Ngô Quyền 84,8 tỷ đồng) so với năm trước chỉ 2,2 tỷ đồng. Lợi nhuận gộp từ bán hàng tăng từ 778 triệu lên 2,56 tỷ đồng. Dòng tiền từ hoạt động kinh doanh âm 18,2 tỷ đồng nhưng dòng tiền đầu tư dương 91,8 tỷ đồng. Các công ty con phần lớn hoạt động không hiệu quả. Nếu không có giao dịch chuyển nhượng bất động sản lớn, kết quả kinh doanh từ hoạt động sản xuất kinh doanh cốt lõi vẫn rất yếu. Triển vọng đầu tư rủi ro cao do phụ thuộc vào các khoản thu nhập bất thường và khả năng hoạt động liên tục còn nhiều dấu hỏi.'),
('VNP_2016_consolidated', 'VNP', 2016, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là mua bán hàng hóa với Công ty Cổ phần Nhựa Vân Đồn và Công ty TNHH Liên Doanh Việt Thái PlastChem, không có dấu hiệu giao dịch bất thường về giá hay lãi suất ưu đãi.', 'Nợ vay lớn, tỷ lệ nợ thuần trên vốn chủ sở hữu là 248,1% cuối năm 2016. Công ty có vay nợ từ nhiều ngân hàng với lãi suất từ 7% đến 3,2%/năm. Có tài sản thế chấp là quyền sử dụng đất và tài sản cố định. Áp lực trả nợ cao nhưng đã giảm so với năm trước.', 'Hàng tồn kho giảm so với đầu năm, dự phòng giảm giá hàng tồn kho cũng giảm. Không có thông tin về tồn kho dở dang hay dự án ứ đọng.', 5, 'Công ty ghi nhận doanh thu giảm 47% so với năm trước nhưng lợi nhuận sau thuế tăng 43%. Dòng tiền từ hoạt động kinh doanh dương mạnh. Nợ vay giảm nhưng vẫn ở mức cao. Có ý kiến kiểm toán ngoại trừ về nợ phải thu. Triển vọng trung bình.'),
('VNP_2016_parent', 'VNP', 2016, 'parent', 'Có giao dịch với các bên liên quan như công ty con, công ty liên kết, nhưng không có dấu hiệu bất thường rõ ràng. Các khoản phải thu và phải trả với giá trị không quá lớn so với tổng tài sản, tuy nhiên cần theo dõi chặt chẽ.', 'Nợ vay giảm từ 265,9 tỷ VNĐ xuống 167,4 tỷ VNĐ, giảm áp lực tài chính. Công ty có thế chấp tài sản cố định và tiền gửi cho khoản vay, nhưng nợ vẫn ở mức cao với tỷ lệ nợ thuần trên vốn chủ sở hữu 690,2%.', 'Tồn kho giảm từ 33,9 tỷ VNĐ xuống 29,1 tỷ VNĐ, dự phòng giảm giá cũng giảm, cho thấy tiêu thụ tốt. Tuy nhiên, còn hàng hóa tồn kho lớn, cần theo dõi nguy cơ ứ đọng.', 5, 'Công ty đã giảm lỗ lũy kế và có lợi nhuận năm 2016, nhưng vẫn còn lỗ lũy kế lớn 171,4 tỷ VNĐ. Nợ vay đã giảm, cải thiện thanh khoản. Tuy nhiên, cần kiểm soát chặt chẽ các khoản phải thu và tồn kho để duy trì hoạt động liên tục.'),
('VNM_2025_consolidated', 'VNM', 2025, 'consolidated', 'Các giao dịch với các bên liên quan (công ty liên kết, cổ đông lớn) chủ yếu là giao dịch mua bán hàng hóa, dịch vụ và nhận cổ tức. Giá trị giao dịch lớn, đặc biệt với Công ty Cổ phần APIS (mua hàng hóa hơn 1,400 tỷ VND) và Tổng Công ty Đầu tư và Kinh doanh Vốn Nhà nước (nhận cổ tức hơn 3,600 tỷ VND). Không có thông tin về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Tổng nợ phải trả chiếm khoảng 35% tổng tài sản, cân đối giữa nợ ngắn hạn (18,520 tỷ) và nợ dài hạn (309 tỷ). Các khoản vay chủ yếu không có đảm bảo, đến từ các ngân hàng lớn. Áp lực thanh toán nợ ngắn hạn ở mức trung bình, dòng tiền từ hoạt động kinh doanh mạnh (hơn 8,600 tỷ) có khả năng bù đắp. Tuy nhiên, tỷ lệ vay/tổng tài sản cần được theo dõi trong bối cảnh lãi suất biến động.', 'Hàng tồn kho tăng mạnh từ 5,687 tỷ lên 6,839 tỷ VND, chủ yếu do tăng nguyên vật liệu và thành phẩm. Dự phòng giảm giá tăng từ 37 tỷ lên 58 tỷ VND, nhưng mức tăng dự phòng (khoảng 21 tỷ) nhỏ hơn nhiều so với mức tăng giá trị hàng tồn kho (hơn 1,100 tỷ), cho thấy doanh nghiệp đang mở rộng quy mô sản xuất kinh doanh. Rủi ro tồn kho dở dang và dự án xây dựng ở mức kiểm soát được.', 2, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) có nền tảng tài chính vững mạnh với tỷ suất lợi nhuận gộp cao (khoảng 41%), doanh thu tăng trưởng ổn định, và vị thế thị trường dẫn đầu. Hệ thống quản trị minh bạch với báo cáo kiểm toán toàn diện từ KPMG. Các giao dịch với bên liên quan có quy mô lớn nhưng được thực hiện trong khuôn khổ kinh doanh thông thường. Khả năng thanh toán nợ tốt, dòng tiền từ hoạt động kinh doanh dồi dào. Các rủi ro chính đến từ biến động tỷ giá (do hoạt động ở nước ngoài) và cạnh tranh thị trường. Nhìn chung, doanh nghiệp có triển vọng đầu tư tích cực.'),
('VNP_2015_consolidated', 'VNP', 2015, 'consolidated', 'Công ty có phát sinh giao dịch mua bán hàng hóa và dịch vụ quy mô lớn với các công ty liên doanh, liên kết (Vân Đồn, Youl Chon Vina, Việt Thái PlastChem, TPC Vina). Điều này đặt ra câu hỏi về tính công bằng của giá giao dịch và có thể ảnh hưởng đến lợi nhuận hợp nhất. Các khoản phải thu từ bên liên quan chiếm tỷ trọng đáng kể trong tổng phải thu, tạo rủi ro tập trung tín dụng.', 'Công ty có đòn bẩy tài chính rất cao (tỷ lệ nợ thuần/vốn chủ sở hữu là 6,42 lần). Nợ vay chủ yếu là ngắn hạn từ nhiều ngân hàng khác nhau, với lãi suất dao động từ 3.2% đến 13%/năm. Công ty thế chấp nhiều tài sản cố định (đất đai, nhà xưởng) và hàng tồn kho để đảm bảo cho các khoản vay. Chi phí lãi vay trong năm 2015 là 21,7 tỷ đồng, tạo áp lực lớn lên dòng tiền hoạt động kinh doanh.', 'Hàng tồn kho chủ yếu là hàng hóa (thành phẩm và hàng hóa mua bán) và nguyên liệu. Công ty đã trích lập dự phòng giảm giá hàng tồn kho hơn 1,4 tỷ đồng, cho thấy một phần hàng hóa có nguy cơ giảm giá trị. Tuy nhiên, mức dự phòng này tương đối nhỏ so với giá trị hàng tồn kho gốc hơn 64 tỷ đồng.', 7, 'Công ty Cổ phần Nhựa Việt Nam có sức khỏe tài chính yếu với đòn bẩy nợ rất cao và lợi nhuận sau thuế chủ yếu đến từ hoạt động tài chính (lãi từ đầu tư vào công ty liên kết) thay vì hoạt động kinh doanh cốt lõi. Dòng tiền từ hoạt động kinh doanh âm trong năm 2015. Rủi ro lớn nhất nằm ở giao dịch với các bên liên quan và gánh nặng nợ vay ngắn hạn. Triển vọng đầu tư tiêu cực do áp lực tài chính và phụ thuộc vào kết quả từ các khoản đầu tư vào công ty liên kết.'),
('VNM_2025_parent', 'VNM', 2025, 'parent', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm công ty con và công ty liên kết, nhưng các giao dịch này chủ yếu là mua bán hàng hóa và dịch vụ trong hoạt động kinh doanh bình thường. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Công ty có nợ vay ngắn hạn lớn với tổng cộng 8.841 tỷ VNĐ, không có tài sản đảm bảo và thời hạn từ 1-12 tháng. Tuy nhiên, công ty có lượng tiền mặt và đầu tư ngắn hạn dồi dào, nên áp lực thanh toán nợ thấp.', 'Hàng tồn kho bao gồm nguyên vật liệu và thành phẩm, với dự phòng giảm giá không đáng kể. Các dự án xây dựng dở dang như nhà máy sữa Nghệ An và Tiên Sơn đang trong quá trình triển khai, không có dấu hiệu ứ đọng.', 5, 'Công ty Cổ phần Sữa Việt Nam là doanh nghiệp hàng đầu trong ngành sữa tại Việt Nam với doanh thu và lợi nhuận ổn định. Tỷ suất lợi nhuận gộp cao, quản lý nợ hiệu quả và hoạt động kinh doanh liên tục tăng trưởng. Tuy nhiên, cần theo dõi rủi ro liên quan đến giao dịch bên liên quan và biến động tỷ giá.'),
('VNM_2024_parent', 'VNM', 2024, 'parent', 'Các giao dịch với bên liên quan chủ yếu là giao dịch thương mại bình thường như mua bán hàng hóa, dịch vụ, chia cổ tức, không có dấu hiệu bất thường về lãi suất hay điều kiện ưu đãi đặc biệt.', 'Nợ vay ngắn hạn ở mức vừa phải, được đảm bảo bởi dòng tiền hoạt động mạnh và lượng tiền mặt, đầu tư ngắn hạn dồi dào, nên rủi ro thanh khoản thấp.', 'Hàng tồn kho giảm so với đầu năm, dự phòng giảm giá hàng tồn kho được điều chỉnh hợp lý, không có dấu hiệu ứ đọng hay rủi ro mất giá nghiêm trọng.', 3, 'Công ty có tình hình tài chính vững mạnh, lợi nhuận tăng trưởng, biên lợi nhuận gộp cao, thanh khoản tốt. Các hoạt động kinh doanh chính hiệu quả, rủi ro tài chính được kiểm soát. Triển vọng đầu tư tích cực.'),
('VNM_2024_consolidated', 'VNM', 2024, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua hàng hóa, dịch vụ và chia cổ tức, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ vay chủ yếu là ngắn hạn với lãi suất không được tiết lộ, nhưng tài sản đảm bảo chỉ áp dụng cho một khoản vay HSBC. Áp lực nợ vay không cao do tỷ lệ nợ trên vốn chủ sở hữu thấp và dòng tiền kinh doanh mạnh.', 'Hàng tồn kho bao gồm nguyên vật liệu, thành phẩm và sản phẩm dở dang, có dự phòng giảm giá nhưng không đáng kể. Không có dấu hiệu tồn kho ứ đọng lớn.', 3, 'Công ty có sức khỏe tài chính tốt với lợi nhuận gộp cao, dòng tiền kinh doanh dồi dào, và nợ vay kiểm soát. Triển vọng đầu tư tích cực nhờ vị thế thị trường vững chắc và tăng trưởng ổn định.'),
('VNM_2023_parent', 'VNM', 2023, 'parent', 'Công ty có nhiều giao dịch lớn với các công ty con và liên kết, đặc biệt trong mua bán hàng hóa, góp vốn và chia cổ tức. Các giao dịch này tập trung và có giá trị lớn, cho thấy sự phụ thuộc và mối quan hệ mật thiết, nhưng không có dấu hiệu giao dịch bất thường rõ ràng về giá hay điều kiện phi thương mại.', 'Nợ vay ngắn hạn tăng mạnh từ 4.337,5 tỷ lên 7.593,3 tỷ VNĐ, chủ yếu từ các ngân hàng lớn. Các khoản vay không có tài sản đảm bảo và có kỳ hạn ngắn (1-12 tháng), tạo áp lực thanh khoản. Tuy nhiên, Công ty có dòng tiền hoạt động kinh doanh mạnh (7.338 tỷ VNĐ) và lượng tiền gửi có kỳ hạn lớn (16.700 tỷ VNĐ ngắn hạn + 150 tỷ dài hạn) làm đệm.', 'Hàng tồn kho tăng từ 4.155 tỷ lên 4.412 tỷ VNĐ, chủ yếu do tăng nguyên vật liệu và thành phẩm. Dự phòng giảm giá hàng tồn kho tăng từ 629 triệu lên 3,1 tỷ VNĐ, cho thấy một phần hàng hóa có nguy cơ chậm luân chuyển hoặc giảm giá trị. Tuy nhiên, đây là mức dự phòng không đáng kể so với tổng giá trị tồn kho.', 2, 'Vinamilk duy trì vị thế tài chính mạnh với biên lợi nhuận gộp cao (~44.4%), dòng tiền hoạt động dồi dào và cơ cấu vốn chủ sở hữu lớn. Tuy nhiên, nợ vay ngắn hạn tăng nhanh đáng chú ý. Các giao dịch bên liên quan là chiến lược và trong ngành, không thấy bất thường. Công ty được kiểm toán bởi KPMG với ý kiến chấp nhận toàn phần, làm tăng độ tin cậy. Triển vọng đầu tư tích cực nhờ thương hiệu mạnh và mạng lưới rộng, nhưng cần theo dõi áp lực nợ ngắn hạn và quản lý tồn kho.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNM_2023_consolidated', 'VNM', 2023, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua bán hàng hóa, dịch vụ và nhận cổ tức từ các công ty liên kết/liên doanh. Giá trị giao dịch mua hàng lớn với Công ty Cổ phần APIS (286 tỷ VND) và Miraka Holdings Limited (229 tỷ VND), song không có dấu hiệu giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá phi thị trường. Các giao dịch này phản ánh hoạt động thương mại bình thường trong chuỗi cung ứng của Tập đoàn.', 'Tổng nợ vay (ngắn hạn và dài hạn) khoảng 8.5 nghìn tỷ VND, trong đó vay ngắn hạn chiếm tỷ trọng lớn (~8.2 nghìn tỷ VND). Tuy nhiên, Tập đoàn có vị thế tiền mặt và tương đương tiền rất mạnh (gần 2.9 nghìn tỷ VND) cùng các khoản đầu tư nắm giữ đến đáo hạn ngắn hạn lên tới hơn 20 nghìn tỷ VND, cho thấy khả năng thanh toán nợ ngắn hạn là rất cao. Phần lớn các khoản vay không có tài sản đảm bảo, chỉ riêng khoản vay tại HSBC Hoa Kỳ được đảm bảo bởi tài sản giá trị ~798 tỷ VND. Áp lực nợ vay ở mức kiểm soát được.', 'Hàng tồn kho có giá trị ghi sổ lớn (~6.1 nghìn tỷ VND), chủ yếu là nguyên vật liệu và thành phẩm. Dự phòng giảm giá hàng tồn kho chỉ ở mức 37.8 tỷ VND, chiếm tỷ trọng nhỏ (<1%), cho thấy chất lượng tồn kho nhìn chung tốt, không có nguy cơ ứ đọng lớn. Các dự án xây dựng cơ bản dở dang (555 tỷ VND) tập trung vào mở rộng nhà máy và trang trại, là đầu tư chiến lược dài hạn, chưa thấy dấu hiệu chậm trễ hay lãng phí.', 3, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) thể hiện sức khỏe tài chính xuất sắc. Công ty có lợi nhuận sau thuế hợp nhất cao (hơn 9,000 tỷ VND năm 2023), biên lợi nhuận gộp ổn định (~41%), và dòng tiền hoạt động kinh doanh mạnh mẽ (~7,900 tỷ VND). Nợ vay được kiểm soát tốt và được bù đắp bởi lượng tiền mặt và đầu tư tài chính dồi dào. Ban lãnh đạo có kinh nghiệm, cổ đông lớn là Tổng Công ty Đầu tư và Kinh doanh Vốn Nhà nước (SCIC) tạo sự ổn định. Rủi ro chính nằm ở biến động giá nguyên liệu đầu vào và cạnh tranh thị trường, nhưng vị thế dẫn đầu và chuỗi cung ứng tích hợp giúp công ty có lợi thế cạnh tranh lớn. Triển vọng đầu tư tích cực.'),
('VNM_2022_consolidated', 'VNM', 2022, 'consolidated', 'Tập đoàn có giao dịch thường xuyên với các công ty liên kết và liên doanh, bao gồm mua bán hàng hóa, dịch vụ, góp vốn và chia cổ tức. Các giao dịch này được thực hiện theo điều kiện thị trường và không có dấu hiệu bất thường như cho vay không lãi suất hay chênh lệch lớn.', 'Nợ vay chủ yếu là ngắn hạn, tập trung vào các ngân hàng nước ngoài. Áp lực nợ vay ở mức trung bình do doanh nghiệp có dòng tiền hoạt động mạnh. Tài sản thế chấp chỉ áp dụng cho khoản vay của HSBC Hoa Kỳ.', 'Hàng tồn kho bao gồm nguyên vật liệu, sản phẩm dở dang và thành phẩm. Dự phòng giảm giá tồn kho ở mức thấp, cho thấy rủi ro ứ đọng không đáng kể. Các dự án xây dựng dở dang đang trong quá trình triển khai.', 5, 'Tập đoàn có tình hình tài chính vững mạnh với doanh thu ổn định, tỷ suất lợi nhuận gộp cao. Nợ vay được quản lý tốt, dòng tiền hoạt động dồi dào. Các giao dịch bên liên quan tuân thủ quy định, không có rủi ro lớn. Triển vọng đầu tư tích cực nhờ vị thế thị trường và hiệu quả hoạt động.'),
('VNM_2022_parent', 'VNM', 2022, 'parent', 'Công ty có mạng lưới giao dịch bên liên quan rộng lớn với các công ty con, liên kết, liên doanh và cổ đông lớn. Các giao dịch chủ yếu là mua bán hàng hóa, dịch vụ, góp vốn, chia cổ tức và bán tài sản. Không có dấu hiệu bất thường rõ ràng về giá chuyển nhượng hay lãi suất ưu đãi đặc biệt, tuy nhiên quy mô giao dịch lớn đòi hỏi giám sát chặt chẽ để đảm bảo tính công bằng và minh bạch.', 'Nợ vay ngắn hạn giảm mạnh từ 8.838,7 tỷ VND đầu năm xuống 4.337,5 tỷ VND cuối năm, phản ánh việc trả nợ đáng kể. Các khoản vay không có đảm bảo và đáo hạn trong 1-12 tháng, cho thấy tính thanh khoản cao và áp lực trả nợ trong ngắn hạn ở mức kiểm soát được. Tuy nhiên, công ty vẫn phụ thuộc vào nguồn vốn vay ngắn hạn từ các ngân hàng quốc tế và trong nước.', 'Hàng tồn kho giảm từ 5.504,5 tỷ VND xuống 4.155,3 tỷ VND, chủ yếu do giảm nguyên vật liệu và thành phẩm. Dự phòng giảm giá hàng tồn kho cũng giảm, cho thấy quản lý tồn kho hiệu quả. Các dự án xây dựng cơ bản dở dang tăng mạnh (từ 185,2 tỷ lên 431,4 tỷ VND), tập trung vào mở rộng nhà máy, cần theo dõi tiến độ và hiệu quả đầu tư.', 3, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) duy trì vị thế tài chính vững mạnh với doanh thu thuần gần 50.000 tỷ VND, tỷ suất lợi nhuận gộp cao (xấp xỉ 44%). Công ty có hệ thống quản trị tốt, nợ vay giảm, dòng tiền hoạt động kinh doanh dương lớn. Rủi ro tập trung ở mạng lưới giao dịch bên liên quan phức tạp và một số dự án đầu tư dài hạn đang triển khai. Nhìn chung, triển vọng tài chính và đầu tư tích cực.'),
('VNM_2021_consolidated', 'VNM', 2021, 'consolidated', 'Các giao dịch với bên liên quan chủ yếu là mua hàng hóa/dịch vụ từ công ty liên kết và nhận cổ tức. Không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá lớn. Rủi ro thấp.', 'Nợ vay ngắn hạn chiếm tỷ trọng lớn (9.382 tỷ VND) với đa dạng các ngân hàng quốc tế, lãi suất không được tiết lộ chi tiết. Tổng nợ vay/vốn chủ sở hữu ở mức 0,26, tương đối an toàn. Dòng tiền hoạt động kinh doanh mạnh (9.432 tỷ VND) đủ bù đắp áp lực nợ. Có một khoản vay ngắn hạn và dài hạn được đảm bảo bằng tài sản.', 'Hàng tồn kho tăng mạnh 38% từ 4.905 tỷ lên 6.773 tỷ VND, chủ yếu do nguyên vật liệu tăng 45%. Dự phòng giảm giá hàng tồn kho ở mức 47 tỷ VND, giảm nhẹ so với đầu năm. Có thể do doanh nghiệp dự trữ nguyên vật liệu sản xuất lớn, cần theo dõi khả năng tiêu thụ.', 4, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) duy trì vị thế dẫn đầu thị trường với biên lợi nhuận gộp cao (43,14%), dòng tiền hoạt động kinh doanh dồi dào và cơ cấu tài chính an toàn. Doanh thu tăng trưởng chậm lại (2%), lợi nhuận sau thuế giảm nhẹ. Nợ vay được kiểm soát tốt, đầu tư vào các công ty con và liên kết mở rộng. Tồn kho tăng cần giám sát. Rủi ro quản trị ở mức trung bình do có nhiều giao dịch với bên liên quan nhưng được công khai minh bạch.'),
('VNM_2020_parent', 'VNM', 2020, 'parent', 'Công ty có giao dịch mua bán hàng hóa, dịch vụ và góp vốn lớn với các công ty con, công ty liên kết (tổng giao dịch bên liên quan năm 2020 khoảng 3,640 tỷ VND). Các khoản phải thu và phải trả thương mại với bên liên quan không tính lãi và có thời hạn thanh toán ngắn (30-60 ngày). Giao dịch chủ yếu là mua nguyên liệu sữa từ các công ty con (Đường Việt Nam, Bò Sữa Việt Nam) và bán hàng cho Angkor Dairy, Vinamilk Europe. Tuy nhiên, tỷ lệ sở hữu tại các công ty con rất cao (100% hoặc trên 75%), nên giao dịch này hợp lý về mặt chiến lược kinh doanh tích hợp chuỗi cung ứng sữa. Không phát hiện giao dịch bất thường rõ ràng.', 'Nợ vay ngắn hạn 6,960 tỷ VND tăng mạnh so với đầu năm (4,875 tỷ VND). Tất cả các khoản vay đều là ngắn hạn (9-12 tháng), bằng ngoại tệ (USD) hoặc VND, không có tài sản đảm bảo. Công ty chủ yếu vay từ các ngân hàng nước ngoài (MUFG, DBS, Sumitomo Mitsui) và Vietcombank. Tuy nhiên, Công ty có lượng tiền gửi ngân hàng kỳ hạn lớn (15,100 tỷ VND ngắn hạn + 200 tỷ VND dài hạn) và tiền mặt 464 tỷ VND, cho thấy khả năng thanh toán nợ tốt. Chi phí lãi vay 108 tỷ VND năm 2020 tương đối thấp so với quy mô hoạt động.', 'Hàng tồn kho tổng giá trị 3,876 tỷ VND (giảm nhẹ so với 3,882 tỷ VND đầu năm). Dự phòng giảm giá tăng từ 5,958 triệu lên 20,247 triệu VND do dự phòng thành phẩm tăng mạnh. Nguyên vật liệu chiếm tỷ trọng lớn (2,379 tỷ VND) phục vụ sản xuất sữa. Dự án xây dựng dở dang 172 tỷ VND không có dấu hiệu ứ đọng nghiêm trọng, với tiến độ chuyển giao tài sản cố định 128 tỷ VND trong năm.', 3, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) là doanh nghiệp đầu ngành sữa tại Việt Nam với kết quả kinh doanh tăng trưởng ổn định (doanh thu thuần 51,532 tỷ VND, lợi nhuận sau thuế 10,729 tỷ VND). Tỷ suất lợi nhuận gộp ~49.3% rất cao, phản ánh sức mạnh thương hiệu và vị thế thị trường. Công ty có hệ sinh thái công ty con, liên kết rộng lớn (10 công ty con, 9 công ty liên kết) phục vụ chuỗi cung ứng sữa tích hợp. Nợ vay tăng nhưng chủ yếu phục vụ hoạt động kinh doanh, với khả năng thanh toán tốt nhờ lượng tiền gửi kỳ hạn lớn. Kiểm toán viên đưa ra ý kiến chấp nhận toàn phần. Rủi ro chính là tỷ lệ vay ngắn hạn cao và phụ thuộc ngoại tệ (USD). Công ty có cổ đông lớn là SCIC (36% vốn nhà nước) và thực hiện chi trả cổ tức đều đặn (6,094 tỷ VND năm 2020).'),
('VNM_2020_consolidated', 'VNM', 2020, 'consolidated', 'Các giao dịch với các bên liên quan chủ yếu là mua bán hàng hóa, dịch vụ và chi trả cổ tức, không phát hiện giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn với các bên liên quan.', 'Tập đoàn có cấu trúc nợ vay đa dạng với cả nợ ngắn hạn và dài hạn, một số khoản vay được đảm bảo bằng tài sản. Áp lực nợ vay ở mức vừa phải nhờ khả năng thanh toán tốt và tài sản lưu động lớn, nhưng tổng nợ vay khá cao.', 'Hàng tồn kho được quản lý tốt với dự phòng giảm giá hợp lý, không có dấu hiệu tồn kho ứ đọng nghiêm trọng. Các dự án xây dựng cơ bản dở dang đang được triển khai đúng tiến độ.', 4, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) là doanh nghiệp đầu ngành sữa tại Việt Nam với lợi nhuận gộp cao và tăng trưởng ổn định. Tình hình tài chính lành mạnh, thanh khoản tốt, và quản trị doanh nghiệp tương đối minh bạch. Tuy nhiên, tập đoàn đang mở rộng quốc tế và tăng cường đầu tư vào chuỗi cung ứng, tiềm ẩn một số rủi ro hoạt động. Triển vọng đầu tư tích cực trong dài hạn nhờ vị thế thị trường vững chắc và năng lực sản xuất mạnh.'),
('VNM_2021_parent', 'VNM', 2021, 'parent', 'Công ty có nhiều giao dịch với các công ty con và công ty liên kết, bao gồm mua hàng hóa, dịch vụ, góp vốn và chia cổ tức. Các giao dịch này nằm trong phạm vi hoạt động kinh doanh bình thường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, quy mô giao dịch lớn, đòi hỏi sự minh bạch và kiểm soát nội bộ chặt chẽ.', 'Nợ ngắn hạn của công ty là 8.838.700.000.000 VND, toàn bộ không có tài sản đảm bảo. Công ty có lượng tiền mặt và đầu tư ngắn hạn lớn, nhưng áp lực trả nợ trong 12 tháng là đáng kể. Việc quản lý dòng tiền và đa dạng hóa nguồn vay là cần thiết để giảm rủi ro thanh khoản.', 'Hàng tồn kho tăng từ 3.856.553.157.650 VND lên 5.504.479.715.927 VND, tăng khoảng 42,7%. Điều này có thể cho thấy sự ứ đọng hàng hóa hoặc mở rộng sản xuất. Dự phòng giảm giá hàng tồn kho ở mức thấp, nhưng cần theo dõi sát sao để tránh mất giá trị.', 4, 'Công ty Cổ phần Sữa Việt Nam có kết quả kinh doanh vững chắc với biên lợi nhuận gộp cao (khoảng 46,5%) và lợi nhuận sau thuế tăng trưởng. Tuy nhiên, nợ ngắn hạn tăng và hàng tồn kho lớn là những rủi ro tiềm ẩn. Ban lãnh đạo có kinh nghiệm, nhưng cần chú trọng quản lý nợ và tồn kho để duy trì sự ổn định tài chính. Triển vọng đầu tư trung hạn tích cực dựa trên thương hiệu mạnh và thị phần lớn.'),
('VNM_2019_consolidated', 'VNM', 2019, 'consolidated', 'Tập đoàn có giao dịch mua hàng hóa với các công ty liên kết (Miraka Holdings, Công ty Cổ phần APIS, Công ty Cổ phần Chế biến Dừa Á Châu) với tổng giá trị khoảng 172,8 tỷ VND. Các khoản phải trả thương mại cho bên liên quan (Công ty Cổ phần APIS: 12,362 triệu VND, Công ty Cổ phần Chế biến Dừa Á Châu: 1,776 triệu VND) không được đảm bảo, không chịu lãi và phải trả trong vòng 60 ngày. Thù lao cho thành viên Hội đồng Quản trị và Ban Điều hành đạt 107,144 triệu VND. Tổng Công ty Đầu tư và Kinh doanh Vốn Nhà nước nhận cổ tức 3,448 tỷ VND. Không có dấu hiệu giao dịch bất thường hay giá chênh lệch lớn với các bên liên quan.', 'Tổng nợ vay là 5,474 tỷ VND (ngắn hạn 5,351 tỷ, dài hạn 122 tỷ). Các khoản vay ngắn hạn chủ yếu từ ngân hàng nước ngoài (Sumitomo Mitsui, Tokyo-Mitsubishi UFJ, HSBC) bằng USD với lãi suất thấp (2.24%-3.52%/năm). Phần lớn khoản vay ngắn hạn (khoảng 5 tỷ VND) không có tài sản đảm bảo, chỉ một phần nhỏ được đảm bảo bằng tài sản cố định và hàng tồn kho. Áp lực trả nợ ngắn hạn cao, tuy nhiên Tập đoàn có lượng tiền và tương đương tiền lớn (2,665 tỷ VND) và đầu tư nắm giữ đến đáo hạn ngắn hạn (12,435 tỷ VND) giúp thanh khoản an toàn.', 'Tổng hàng tồn kho đạt 4,983 tỷ VND (giảm từ 5,525 tỷ VND đầu năm), trong đó nguyên vật liệu chiếm 2,661 tỷ VND và thành phẩm 1,340 tỷ VND. Dự phòng giảm giá hàng tồn kho chỉ 13 tỷ VND, tỷ lệ rất thấp. Xây dựng cơ bản dở dang 694 tỷ VND bao gồm các dự án chăn nuôi bò sữa tại Thanh Hóa và Công ty Bò sữa Việt Nam. Chi phí SXKD dở dang 249 tỷ VND là bò sữa chưa trưởng thành. Rủi ro tồn kho thấp do chủ yếu là nguyên liệu và thành phẩm sữa có tính thanh khoản cao.', 2, 'Vinamilk là doanh nghiệp đầu ngành sữa Việt Nam với sức khỏe tài chính xuất sắc. Doanh thu thuần năm 2019 đạt 56,318 tỷ VND (tăng 7.1%), lợi nhuận gộp biên đạt 47.2%. Công ty có dòng tiền hoạt động kinh doanh mạnh (11,409 tỷ VND), lượng tiền mặt và đầu tư ngắn hạn dồi dào. Nợ vay chủ yếu bằng ngoại tệ với lãi suất thấp, khả năng thanh toán tốt. Công ty thực hiện nhiều thương vụ M&A (mua 75% GTNFoods với giá 3,460 tỷ VND) để mở rộng kinh doanh. Cổ tức chi trả đều đặn (7,836 tỷ VND trong năm). Điểm rủi ro quản trị thấp do cơ cấu cổ đông minh bạch, giao dịch bên liên quan không đáng kể so với quy mô doanh nghiệp.'),
('VNM_2018_consolidated', 'VNM', 2018, 'consolidated', 'Giao dịch với bên liên quan chủ yếu là mua bán hàng hóa và góp vốn với công ty liên kết. Giá trị mua hàng hóa với Công ty Cổ phần APIS và Miraka Limited là đáng kể (tương ứng 369 tỷ và 92 tỷ VND). Giao dịch thù lao cho thành viên Hội đồng Quản trị và Ban Điều hành là 105 tỷ VND. Cần theo dõi tính công bằng của các giao dịch mua bán với công ty liên kết.', 'Tổng nợ vay khoảng 1.276 tỷ VND, trong đó nợ ngắn hạn chiếm tỷ trọng lớn (1.060 tỷ). Các khoản vay chủ yếu từ các ngân hàng lớn với lãi suất từ 4,11% đến 6,00%/năm. Một số khoản vay được đảm bảo bằng tài sản cố định và phải thu. Áp lực trả nợ ngắn hạn ở mức trung bình.', 'Hàng tồn kho tăng mạnh từ 4.041 tỷ lên 5.538 tỷ VND, chủ yếu do nguyên vật liệu và hàng mua đang đi trên đường tăng. Dự phòng giảm giá hàng tồn kho giảm từ 20,2 tỷ xuống 12,5 tỷ VND. Xây dựng cơ bản dở dang giảm mạnh do chuyển sang tài sản cố định, cho thấy tiến độ triển khai dự án tốt.', 3, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) có kết quả kinh doanh ổn định với doanh thu thuần năm 2018 đạt 52.562 tỷ VND và lợi nhuận sau thuế đạt 10.206 tỷ VND. Biên lợi nhuận gộp ở mức cao (~46,8%). Công ty có cơ cấu tài sản vững mạnh với tiền và đầu tư tài chính lớn. Tuy nhiên, nợ vay ngắn hạn tăng mạnh cần được theo dõi. Công ty đang mở rộng hoạt động đầu tư và sản xuất thông qua các dự án xây dựng và mua lại công ty. Quản trị doanh nghiệp tương đối minh bạch với các giao dịch bên liên quan được công bố rõ ràng.'),
('VNM_2019_parent', 'VNM', 2019, 'parent', 'Các giao dịch với bên liên quan chủ yếu là mua bán hàng hóa và tài sản cố định, cũng như góp vốn vào công ty con và liên kết. Giá trị giao dịch lớn, nhưng không có dấu hiệu bất thường rõ ràng như cho vay không lãi suất hay mua bán chênh lệch lớn. Tuy nhiên, số lượng giao dịch nhiều và giá trị cao đòi hỏi giám sát chặt chẽ.', 'Công ty có khoản vay ngắn hạn lớn 4.875.100.000.000 VND, nhưng lãi suất thấp (2,24% – 3,36% một năm) và không có tài sản thế chấp. Công ty có đủ tiền mặt và đầu tư ngắn hạn để thanh toán, nên áp lực nợ không cao.', 'Hàng tồn kho có dự phòng giảm giá nhưng tỷ trọng nhỏ so với giá trị. Các dự án xây dựng dở dang có tiến độ triển khai, không bị ứ đọng lớn, rủi ro trung bình.', 3, 'Công ty có sức khỏe tài chính tốt với doanh thu và lợi nhuận tăng trưởng. Dòng tiền hoạt động kinh doanh mạnh, thanh khoản cao. Tuy nhiên, cần theo dõi các giao dịch liên quan và nợ ngắn hạn. Triển vọng đầu tư tích cực do vị thế thị trường và hiệu quả hoạt động.');
INSERT OR REPLACE INTO `financial_insights` (`id`, `ticker`, `year`, `report_type`, `related_party_risk`, `debt_risk`, `inventory_risk`, `governance_risk_score`, `overall_analysis`) VALUES
('VNM_2016_parent', 'VNM', 2016, 'parent', 'Công ty có giao dịch mua bán hàng hóa, tài sản cố định và góp vốn với các công ty con và công ty liên kết. Giá trị giao dịch lớn, tuy nhiên các giao dịch này được ghi nhận theo giá thị trường và có đầy đủ thuyết minh. Rủi ro giao dịch bên liên quan ở mức trung bình, không phát hiện dấu hiệu giao dịch bất thường.', 'Công ty chỉ có khoản nợ ngắn hạn với tổng giá trị 1.200 tỷ VND, không có nợ dài hạn. Các khoản vay không được đảm bảo bằng tài sản. Công ty có lượng tiền mặt và đầu tư tài chính ngắn hạn lớn (gần 10.854 tỷ VND), đảm bảo khả năng thanh khoản tốt. Áp lực nợ vay thấp.', 'Hàng tồn kho tăng 18% so với đầu năm, chủ yếu do nguyên vật liệu và thành phẩm tăng. Công ty có dự phòng giảm giá hàng tồn kho 16.67 tỷ VND. Các dự án xây dựng dở dang trị giá 430 tỷ VND, trong đó các nhà máy sữa đang trong quá trình đầu tư xây dựng. Rủi ro tồn kho thấp.', 3, 'Vinamilk là công ty sữa lớn nhất Việt Nam với sức khỏe tài chính vững mạnh. Công ty có biên lợi nhuận gộp cao (khoảng 48.6%), nợ vay thấp, thanh khoản tốt. Giao dịch bên liên quan tuy lớn nhưng là giao dịch thương mại bình thường trong chuỗi sản xuất kinh doanh. Công ty có 6 công ty con và 3 công ty liên kết, mở rộng quy mô hoạt động. Triển vọng đầu tư tích cực trong dài hạn.'),
('VNM_2016_consolidated', 'VNM', 2016, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là mua bán hàng hóa, cung cấp dịch vụ và góp vốn, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Rủi ro thấp.', 'Nợ vay chủ yếu từ ngân hàng với lãi suất hợp lý, có tài sản thế chấp cho một số khoản. Áp lực nợ ngắn hạn cao nhưng khả năng thanh toán tốt nhờ dòng tiền mạnh từ hoạt động kinh doanh.', 'Hàng tồn kho bao gồm nguyên vật liệu và thành phẩm, có dự phòng giảm giá. Xây dựng cơ bản dở dang cho các dự án như trang trại bò sữa, không có dấu hiệu ứ đọng nghiêm trọng.', 3, 'Tập đoàn có tình hình tài chính mạnh với doanh thu và lợi nhuận tăng trưởng tốt trong năm 2016. Quản trị rủi ro hiệu quả, tỷ suất lợi nhuận gộp cao, và triển vọng đầu tư tích cực nhờ vào thị trường sữa nội địa và xuất khẩu.'),
('VNM_2018_parent', 'VNM', 2018, 'parent', 'Giao dịch với bên liên quan chủ yếu là mua bán hàng hóa và tài sản, không có lãi suất, không đảm bảo, nhưng giá trị lớn. Rủi ro thấp do minh bạch và tuân thủ quy định.', 'Nợ vay ngắn hạn 700 tỷ VND, lãi suất thấp, không có đảm bảo, thời hạn ngắn. Áp lực nợ thấp.', 'Hàng tồn kho có dự phòng giảm giá nhỏ, xây dựng cơ bản dở dang giảm mạnh so với đầu năm, cho thấy quản lý tồn kho hiệu quả.', 3, 'Công ty có kết quả kinh doanh tốt với lợi nhuận gộp cao, dòng tiền từ hoạt động kinh doanh mạnh. Tình hình tài chính ổn định, triển vọng đầu tư tích cực.'),
('VNM_2017_consolidated', 'VNM', 2017, 'consolidated', 'Các giao dịch với bên liên quan (công ty liên kết, ban lãnh đạo) có quy mô lớn, chủ yếu là mua bán hàng hóa, dịch vụ và thù lao. Không có bằng chứng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch giá bất thường. Rủi ro ở mức trung bình.', 'Tổng nợ vay ngắn và dài hạn giảm mạnh so với đầu năm (từ 1.659 tỷ xuống 543 tỷ). Áp lực nợ vay giảm rõ rệt, thanh khoản tốt (tiền và tương đương tiền tăng). Có một số khoản vay ngoại tệ (USD) tồn tại rủi ro tỷ giá. Tài sản thế chấp bao gồm tiền gửi có kỳ hạn, TSCĐ hữu hình và vô hình.', 'Hàng tồn kho giảm nhẹ. Dự phòng giảm giá hàng tồn kho tăng từ 16,6 tỷ lên 20,2 tỷ. Các dự án xây dựng cơ bản dở dang (TBĐ, trang trại bò sữa) đang được triển khai và chiếm tỷ trọng lớn trong tài sản dài hạn, nhưng chưa có dấu hiệu ứ đọng.', 3, 'Tập đoàn Sữa Việt Nam (Vinamilk) có sức khỏe tài chính rất tốt năm 2017. Doanh thu thuần và lợi nhuận sau thuế tăng trưởng mạnh (lần lượt ~9% và ~10%). Nợ vay giảm mạnh, dòng tiền hoạt động kinh doanh dồi dào, cho phép trả cổ tức lớn và mua cổ phiếu quỹ. Công ty đang trong giai đoạn mở rộng đầu tư (mua lại Đường Khánh Hòa, tăng vốn tại Angkormilk). Rủi ro chính đến từ tỷ giá đối với các khoản vay nước ngoài và áp lực triển khai các dự án đầu tư lớn. Triển vọng đầu tư tích cực.'),
('VNM_2015_parent', 'VNM', 2015, 'parent', 'Doanh nghiệp có nhiều giao dịch mua bán và góp vốn với các công ty con và liên kết với giá trị lớn, đặc biệt là giao dịch mua hàng hóa với Miraka Limited (456 tỷ VND) và Vinamilk Europe (735 tỷ VND). Các giao dịch này cần được kiểm soát chặt chẽ để đảm bảo tính minh bạch và tránh xung đột lợi ích.', 'Công ty có nợ vay ngắn hạn 1.242 tỷ VND với lãi suất thấp (1.28%/năm) và không có tài sản đảm bảo, cho thấy khả năng tiếp cận vốn tốt. Tuy nhiên, nợ ngắn hạn chiếm tỷ trọng cao trong tổng nợ, đòi hỏi quản lý dòng tiền chặt chẽ.', 'Hàng tồn kho có dự phòng giảm giá 17 tỷ VND, chủ yếu ở nguyên vật liệu và thành phẩm. Xây dựng cơ bản dở dang 277 tỷ VND với nhiều dự án lớn (Nhà máy Sữa Lam Sơn, Tiên Sơn) có thể gặp rủi ro chậm tiến độ hoặc đội vốn.', 5, 'Công ty có tình hình tài chính khỏe mạnh với doanh thu tăng trưởng 16.7%, lợi nhuận sau thuế tăng 28%. Tuy nhiên, cần lưu ý giao dịch lớn với bên liên quan và áp lực từ nợ ngắn hạn. Hàng tồn kho và xây dựng dở dang cần được quản lý chặt để tránh rủi ro.'),
('VNM_2015_consolidated', 'VNM', 2015, 'consolidated', 'Giao dịch với các bên liên quan chủ yếu là mua bán hàng hóa và góp vốn với công ty liên kết Miraka Limited và Công ty Cổ phần Nguyên liệu Thực phẩm Á Châu Sài Gòn. Các giao dịch này được thực hiện theo giá thị trường, không có dấu hiệu bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn. Cổ tức cho cổ đông lớn là Tổng Công ty Đầu tư và Kinh doanh Vốn Nhà nước là hợp lý. Do đó, rủi ro từ giao dịch bên liên quan thấp.', 'Nợ vay của Tập đoàn được đảm bảo bằng tài sản (hàng tồn kho và phải thu) cho một số khoản vay, với lãi suất thấp (dưới 3%/năm). Tổng nợ vay ngắn hạn và dài hạn ở mức kiểm soát, và Tập đoàn có đủ dòng tiền từ hoạt động kinh doanh để trả nợ. Tuy nhiên, một phần nợ bằng ngoại tệ (USD, EUR) có thể chịu rủi ro tỷ giá, nhưng đã được phòng ngừa bằng hợp đồng kỳ hạn. Nhìn chung, áp lực nợ vay không đáng lo ngại.', 'Hàng tồn kho bao gồm nguyên vật liệu, thành phẩm và hàng hóa, với dự phòng giảm giá đã được lập. Dự trữ bò sữa (chi phí sản xuất kinh doanh dở dang) tăng, cho thấy hoạt động chăn nuôi mở rộng. Xây dựng cơ bản dở dang cho các dự án như nhà máy và trang trại, cho thấy đầu tư vào năng lực sản xuất. Không có dấu hiệu ứ đọng lớn, nhưng cần theo dõi tiến độ dự án.', 3, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) là công ty sữa hàng đầu với lợi nhuận mạnh mẽ và tăng trưởng doanh thu. Tỷ suất lợi nhuận gộp cao, quản lý nợ hiệu quả và dòng tiền hoạt động dồi dào. Các giao dịch bên liên quan minh bạch, không có rủi ro đáng kể. Mặc đầu tư vào mở rộng sản xuất, công ty duy trì vị thế tài chính vững chắc. Triển vọng đầu tư tích cực dựa trên thị phần lớn và thương hiệu mạnh.'),
('VNM_2017_parent', 'VNM', 2017, 'parent', 'Công ty có nhiều giao dịch lớn với các công ty con và liên kết, bao gồm mua hàng hóa (tổng trên 1.900 tỷ VND), mua bán tài sản cố định và góp vốn. Các khoản phải thu và phải trả với bên liên quan không hưởng lãi và không có tài sản đảm bảo. Giá trị mua hàng từ công ty con Bò Sữa Việt Nam đạt hơn 1.000 tỷ VND và từ Vinamilk Europe đạt hơn 667 tỷ VND. Tuy nhiên, các giao dịch này phù hợp với chuỗi cung ứng nguyên liệu sữa nội bộ, chưa thấy dấu hiệu giao dịch bất thường đáng kể. Lợi nhuận từ sáp nhập Sữa Lam Sơn (431 tỷ VND) phát sinh chủ yếu từ lợi nhuận lũy kế của công ty con bị sáp nhập.', 'Công ty không còn nợ vay ngắn hạn tại cuối năm 2017 (đã trả toàn bộ 1.200 tỷ VND) và không có nợ vay dài hạn. Tuy nhiên, Công ty có nghĩa vụ phải trả ngắn hạn lớn (9.112 tỷ VND), trong đó phải trả ngắn hạn khác chiếm 3.023 tỷ VND bao gồm khoản trả trước nhận từ bên thứ ba về chuyển nhượng đầu tư (448 tỷ VND) và phải trả mua cổ phần Đường Việt Nam (286 tỷ VND). Công ty có mức thanh khoản tốt với tiền gửi ngân hàng và tương đương tiền đạt 733 tỷ VND cùng đầu tư nắm giữ đáo hạn ngắn hạn hơn 10.073 tỷ VND.', 'Hàng tồn kho giảm từ 4.099 tỷ VND xuống 3.448 tỷ VND (-16%), dự phòng giảm giá giảm từ 16,7 tỷ xuống 4,8 tỷ VND. Nguyên vật liệu chiếm phần lớn (2.072 tỷ VND), phù hợp với đặc thù sản xuất sữa. Xây dựng cơ bản dở dang tăng mạnh từ 430 tỷ lên 971 tỷ VND (+126%), phản ánh chiến lược mở rộng công suất tại Nhà máy Nước Giải Khát (340 tỷ), Nhà máy Sữa Việt Nam (158 tỷ) và Nhà máy Sữa Sài Gòn (142 tỷ). Các dự án này cho thấy doanh nghiệp đang tích cực đầu tư mở rộng sản xuất.', 3, 'Công ty Cổ phần Sữa Việt Nam (Vinamilk) có tình hình tài chính lành mạnh với biên lợi nhuận gộp ~48,9%, lợi nhuận sau thuế đạt 10.545 tỷ VND (tăng 14% so với năm trước). Công ty không có nợ vay, tỷ lệ nợ/vốn chủ sở hữu thấp (Nợ phải trả 9.213 tỷ VND / Vốn chủ sở hữu 23.296 tỷ VND). Dòng tiền từ hoạt động kinh doanh dồi dào (10.042 tỷ VND). Công ty đang tích cực mở rộng qua sáp nhập (Sữa Lam Sơn) và mua cổ phần (Đường Việt Nam, Angkor Dairy). Cổ tức chi trả lớn (7.982 tỷ VND). Điểm rủi ro quản trị ở mức thấp do ban lãnh đạo minh bạch, tuy nhiên các giao dịch với công ty con và liên kết lớn, cần theo dõi.'),
('VNL_2025_consolidated', 'VNL', 2025, 'consolidated', 'Công ty có các giao dịch với các bên liên quan bao gồm cung cấp dịch vụ, mua dịch vụ và nhận cổ tức. Các giao dịch này được thực hiện theo giá thỏa thuận, không có dấu hiệu bất thường. Tuy nhiên, công ty có mối quan hệ phức tạp với nhiều công ty liên kết/liên doanh, đòi hỏi sự giám sát.', 'Công ty không có nợ vay ngân hàng mà chủ yếu là nợ phải trả thương mại. Tuy nhiên, có khoản nợ dài hạn liên quan đến tạm ứng đền bù di dời từ Công ty Cổ phần Đường Khánh Hội, hiện đang liên quan đến vụ án hình sự, có thể gây rủi ro pháp lý.', 'Công ty không có hàng tồn kho, do đó không có rủi ro tồn kho.', 4, 'Công ty kinh doanh logistics, doanh thu và lợi nhuận tăng trưởng 21% so với năm trước. Sức khỏe tài chính cơ bản tốt với tỷ suất lợi nhuận gộp khoảng 6.9%, không có nợ vay ngân hàng. Tuy nhiên, công ty đang đối mặt với rủi ro pháp lý liên quan đến khoản tạm ứng đền bù di dời từ Công ty Cổ phần Đường Khánh Hội. Triển vọng đầu tư ở mức trung bình.'),
('VNL_2022_consolidated', 'VNL', 2022, 'consolidated', 'Doanh nghiệp có giao dịch với các bên liên quan bao gồm cung cấp dịch vụ, nhận dịch vụ và chia cổ tức. Giá dịch vụ theo thỏa thuận, nhưng cần đánh giá tính công bằng. Kiểm toán có ý kiến ngoại trừ về xác nhận công nợ với Công ty Cổ phần Đường Khánh Hội liên quan đến khoản tạm ứng tiền đền bù di dời, cho thấy rủi ro về giao dịch với bên liên quan.', 'Nợ vay giảm so với đầu năm, nhưng có khoản nợ dài hạn lớn liên quan đến dự án với Công ty Cổ phần Đường Khánh Hội. Áp lực nợ vay không cao nhờ dòng tiền kinh doanh tốt.', 'Công ty không có hàng tồn kho, do đó rủi ro tồn kho thấp.', 5, 'Lợi nhuận sau thuế tăng trưởng 16.35% so với năm trước, nhưng tăng trưởng doanh thu giảm do ảnh hưởng của đại dịch COVID-19. Kiểm toán có ý kiến ngoại trừ, nhưng công ty có sức khỏe tài chính cơ bản tốt với vốn chủ sở hữu tăng và nợ vay giảm.'),
('VNL_2024_consolidated', 'VNL', 2024, 'consolidated', 'Công ty có nhiều giao dịch với các bên liên quan bao gồm cung cấp và nhận dịch vụ, chia cổ tức. Giá dịch vụ theo thỏa thuận, có nguy cơ giao dịch không theo giá thị trường. Tuy nhiên, không có bằng chứng rõ ràng về giao dịch bất thường như cho vay không lãi suất hay mua bán chênh lệch lớn.', 'Nợ phải trả chủ yếu là nợ thương mại và thuế, không có nợ vay ngân hàng rõ ràng. Tỷ lệ nợ trên vốn chủ sở hữu khoảng 0.53, ở mức trung bình. Áp lực thanh toán nợ ngắn hạn có thể được bù đắp bởi tiền mặt hiện có, nhưng rủi ro thanh toán vẫn tồn tại do nợ thương mại chiếm tỷ trọng lớn.', 'Công ty hoạt động trong lĩnh vực logistics, không có hàng tồn kho vật chất hoặc dự án xây dựng dở dang, do đó rủi ro tồn kho thấp.', 5, 'Công ty có sự tăng trưởng doanh thu và lợi nhuận trong năm 2024, tỷ suất lợi nhuận gộp khoảng 7%. Tình hình tài chính ổn định với tỷ lệ nợ thấp. Tuy nhiên, rủi ro liên quan đến giao dịch bên liên quan và sự kiện pháp lý với Công ty Cổ phần Đường Khánh Hội cần được theo dõi. Triển vọng đầu tư trung bình.');
PRAGMA foreign_keys = ON;
